struct SingleUseProcedureInlineResult {
  std::vector<MachineItem> items;
  int inlined = 0;
};

SingleUseProcedureInlineResult
inline_single_use_procedures(std::vector<MachineItem> items) {
  SingleUseProcedureInlineResult result{.items = std::move(items)};
  bool changed = true;
  while (changed) {
    changed = false;
    for (std::size_t start = 0; start < result.items.size(); ++start) {
      const MachineItem& boundary = result.items.at(start);
      if (boundary.kind != MachineItemKind::Label || boundary.procedure_boundary != "start" ||
          !boundary.procedure_name.has_value()) {
        continue;
      }
      const std::string entry = *boundary.procedure_name;
      std::size_t end = start + 1U;
      while (end < result.items.size() &&
             !(result.items.at(end).kind == MachineItemKind::Label &&
               result.items.at(end).procedure_boundary == "end" &&
               result.items.at(end).procedure_name == entry)) {
        if (result.items.at(end).procedure_boundary == "start")
          break;
        ++end;
      }
      if (end >= result.items.size() || result.items.at(end).procedure_boundary != "end")
        continue;

      std::set<std::string> local_labels{entry, result.items.at(end).name};
      bool body_safe = true;
      std::optional<std::size_t> terminal_return;
      for (std::size_t index = start + 1U; index < end; ++index) {
        const MachineItem& item = result.items.at(index);
        if (item.kind == MachineItemKind::Label) {
          local_labels.insert(item.name);
          continue;
        }
        if (item.raw || item.manual_interaction.has_value()) {
          body_safe = false;
          break;
        }
        if (item.kind == MachineItemKind::Op && item.opcode == 0x52) {
          if (terminal_return.has_value()) {
            body_safe = false;
            break;
          }
          terminal_return = index;
        }
      }
      if (!body_safe || !terminal_return.has_value())
        continue;
      for (std::size_t index = *terminal_return + 1U; index < end; ++index) {
        if (result.items.at(index).kind != MachineItemKind::Label) {
          body_safe = false;
          break;
        }
      }
      if (!body_safe)
        continue;

      std::optional<std::size_t> call_op;
      int entry_references = 0;
      for (std::size_t index = 0; index < result.items.size(); ++index) {
        const MachineItem& item = result.items.at(index);
        if (item.kind == MachineItemKind::Address) {
          if (const auto* target = std::get_if<std::string>(&item.target);
              target != nullptr && *target == entry) {
            ++entry_references;
            if (index > 0U && result.items.at(index - 1U).kind == MachineItemKind::Op &&
                result.items.at(index - 1U).opcode == 0x53 &&
                result.items.at(index - 1U).semantic_call_origins.empty()) {
              call_op = index - 1U;
            }
          }
        }
      }
      if (entry_references != 1 || !call_op.has_value() ||
          (*call_op >= start && *call_op <= end)) {
        continue;
      }

      const MachineItem* predecessor = nullptr;
      for (std::size_t index = *call_op; index > 0U; --index) {
        const MachineItem& item = result.items.at(index - 1U);
        if (item.kind == MachineItemKind::Label)
          continue;
        if (item.kind == MachineItemKind::Op)
          predecessor = &item;
        break;
      }
      const MachineItem* first_body_op = nullptr;
      for (std::size_t index = start + 1U; index < *terminal_return; ++index) {
        const MachineItem& item = result.items.at(index);
        if (item.kind == MachineItemKind::Label)
          continue;
        if (item.kind == MachineItemKind::Op)
          first_body_op = &item;
        break;
      }
      if (predecessor != nullptr && predecessor->opcode == 0x50 &&
          predecessor->stop_disposition == StopDisposition::Resumable &&
          first_body_op != nullptr && first_body_op->opcode >= 0x00 &&
          first_body_op->opcode <= 0x0c) {
        continue;
      }

      for (std::size_t index = 0; index < result.items.size() && body_safe; ++index) {
        if (index >= start && index <= end)
          continue;
        const MachineItem& item = result.items.at(index);
        if (item.kind == MachineItemKind::Address) {
          if (const auto* target = std::get_if<std::string>(&item.target);
              target != nullptr && local_labels.contains(*target) && *target != entry) {
            body_safe = false;
          }
        }
        if (item.indirect_flow_targets.has_value()) {
          for (const IrTarget& target : *item.indirect_flow_targets) {
            if (const auto* label = std::get_if<std::string>(&target);
                label != nullptr && local_labels.contains(*label)) {
              body_safe = false;
              break;
            }
          }
        }
      }
      if (!body_safe)
        continue;

      std::vector<MachineItem> body;
      body.reserve(end - start);
      for (std::size_t index = start + 1U; index < end; ++index) {
        if (index == *terminal_return)
          continue;
        MachineItem item = result.items.at(index);
        item.procedure_boundary.reset();
        item.procedure_name.reset();
        body.push_back(std::move(item));
      }

      std::vector<MachineItem> rewritten;
      rewritten.reserve(result.items.size() + body.size() - (end - start + 1U) - 2U);
      for (std::size_t index = 0; index < result.items.size(); ++index) {
        if (index == *call_op) {
          rewritten.insert(rewritten.end(), body.begin(), body.end());
          ++index;
          continue;
        }
        if (index == start) {
          index = end;
          continue;
        }
        rewritten.push_back(std::move(result.items.at(index)));
      }
      result.items = std::move(rewritten);
      ++result.inlined;
      changed = true;
      break;
    }
  }
  return result;
}

CompileResult compile_source_once(std::string source, const CompileOptions& requested_options,
                                  bool source_has_entered,
                                  bool apply_final_layout_size_rescue = false,
                                  bool apply_atomic_absolute_dark_rescue = false,
                                  std::string* final_layout_input_fingerprint = nullptr) {
  if (final_layout_input_fingerprint != nullptr)
    final_layout_input_fingerprint->clear();
  CompileOptions options = requested_options;
  CompileResult result;
  result.implemented = true;
  result.feature_profile = options.feature_profile;
  result.budget = options.budget;
  auto trace_stage = [](std::string_view) {};

  ProgramAst ast;
  try {
    trace_stage("parse");
    ast = parse_program(
        source, ParseOptions{
                    .signed_abs_match_pairs = options.signed_abs_match_pairs,
                    .synthesize_parametric_siblings = options.synthesize_parametric_siblings,
                    .segmented_bitplanes = options.segmented_bitplanes,
                });
  } catch (const ParseError& error) {
    result.implemented = false;
    result.diagnostics.push_back(
        diagnostic(DiagnosticSeverity::Error, "parse-error", error.what()));
    return result;
  }

  if (ast.feature_profile.has_value()) {
    if (requested_options.feature_profile != FeatureProfile::Standard &&
        requested_options.feature_profile != *ast.feature_profile) {
      result.implemented = false;
      result.diagnostics.push_back(diagnostic(
          DiagnosticSeverity::Error, "feature-profile-conflict",
          "Source feature profile '" + std::string(feature_profile_id(*ast.feature_profile)) +
              "' conflicts with requested feature profile '" +
              std::string(feature_profile_id(requested_options.feature_profile)) + "'"));
      return result;
    }
    options.feature_profile = *ast.feature_profile;
    result.feature_profile = options.feature_profile;
  }

  if (!ast.v2.has_value()) {
    result.implemented = false;
    result.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                            "Native compiler currently supports V2 programs only"));
    return result;
  }
  rewrite_packed_decimal_zero_run_floor_access(*ast.v2);
  trace_stage("validated");

  validate_v2_return_contracts(*ast.v2, result.diagnostics);
  validate_v2_function_call_contracts(*ast.v2, result.diagnostics);
  validate_startup_stack_input_contracts(*ast.v2, result.diagnostics);
  if (has_errors(result.diagnostics)) {
    result.implemented = false;
    return result;
  }
  lower_small_case_matches(*ast.v2);
  materialize_rule_param_state_fields(*ast.v2);

  LoweringContext context;
  context.program = &*ast.v2;
  context.feature_profile = optimizer_feature_profile_for_options(options);
  context.standard_rf_overflow_allocation =
      options.feature_profile == FeatureProfile::Standard &&
      context.feature_profile == FeatureProfile::Mk61SMiniExpanded &&
      options.collect_coalesce_shares;
  context.provisional_logical_register_allocation = options.collect_logical_register_allocation;
  for (const LogicalRegisterAssignment& assignment : options.forced_logical_register_assignments) {
    try {
      context.forced_logical_register_indices[assignment.name] =
          register_index(assignment.register_name);
      if (assignment.preload_owner)
        context.forced_logical_preload_owners.insert(assignment.name);
    } catch (const std::exception&) {
      context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                               "Invalid forced logical register '" +
                                                   assignment.register_name + "' for '" +
                                                   assignment.name + "'."));
    }
  }
  context.emitter.address_space_model = address_space_model_for_options(options);
  context.cave_sketch_shape = false;
  context.segmented_bitplanes = options.segmented_bitplanes;
  context.segmented_line_count_scan = options.segmented_line_count_scan;
  context.stack_resident_temps = options.stack_resident_temps;
  context.stack_argument_helper_entries = options.stack_argument_helper_entries;
  context.stack_argument_function_entries = options.stack_argument_function_entries;
  context.setup_only_counted_loop_init = options.setup_only_counted_loop_init;
  context.x_param_value_functions = options.x_param_value_functions;
  context.x_param_y_stack_stored_entry = options.x_param_y_stack_stored_entry;
  context.packed_score_accumulator_helpers = options.packed_score_accumulator_helpers;
  context.shared_bit_mask_helper_calls = options.shared_bit_mask_helper_calls;
  context.compact_bit_mask_helper_body = options.compact_bit_mask_helper_body;
  context.domain_error_guards = options.domain_error_guards;
  context.show_read_guarded_transfer = options.show_read_guarded_transfer;
  context.comparison_guarded_update_selectors = options.comparison_guarded_update_selectors;
  context.indirect_underflow_decrement = options.indirect_underflow_decrement;
  context.recall_stored_input_after_decrement = options.recall_stored_input_after_decrement;
  context.dead_source_residual_temp_reuse = options.dead_source_residual_temp_reuse;
  context.single_bit_mask_op_copy_reuse = options.single_bit_mask_op_copy_reuse;
  context.share_random_cell = options.share_random_cell;
  context.hoist_shared_helpers = options.hoist_shared_helpers;
  context.hoist_procs = options.hoist_procs;
  context.aggressive_terminal_direct = options.aggressive_terminal_direct;
  context.aggressive_post_layout_indirect_flow = options.aggressive_post_layout_indirect_flow;
  context.preloaded_indirect_flow = options.preloaded_indirect_flow;
  context.disable_candidate_search = options.disable_candidate_search;
  context.free_residual_dispatch_scratch = options.free_residual_dispatch_scratch;
  context.invert_branch_order = options.invert_branch_order;
  context.preserve_dispatch_case_order = options.preserve_dispatch_case_order;
  context.order_procs_by_call_count = options.order_procs_by_call_count;
  context.assume_dead_selector_integer_part = options.assume_dead_selector_integer_part;
  context.synthesized_dispatch_plans = options.synthesized_dispatch_plans;
  context.proc_layout_strategy = options.proc_layout_strategy;
  context.fractional_constant_selectors = options.fractional_constant_selectors;
  for (const auto& [register_name, value] : options.preloaded_constant_registers)
    reserve_preloaded_number_at(context, register_name, value);
  for (const std::string& value : options.suppress_constant_preloads)
    context.suppress_constant_preloads.insert(normalize_number_key(value));
  for (const std::string& value : options.reserve_suppressed_constant_preload_slots)
    context.reserve_suppressed_constant_preload_slots.insert(normalize_number_key(value));
  if (options.strict) {
    const std::set<std::string> no_ignored_targets;
    warn_undeclared_allocations(*ast.v2, true, no_ignored_targets, context.diagnostics);
  }
  bool exact_decimal_series = false;
  try {
    trace_stage("ast-passes");
    const core::ConstantFoldResult early_folded_constants =
        core::fold_program_constants(*ast.v2, {}, core::ConstantFoldMode::DecimalPowersOnly);
    if (early_folded_constants.applied > 0) {
      context.optimizations.push_back(OptimizationReport{
          .name = "early-decimal-power-constant-folder",
          .detail = "Folded " + std::to_string(early_folded_constants.applied) +
                    " constant expression node" +
                    (early_folded_constants.applied == 1 ? "" : "s") +
                    " before structural optimization.",
      });
    }
    if (early_folded_constants.grd_angle_assumptions > 0) {
      context.optimizations.push_back(OptimizationReport{
          .name = "grd-angle-mode-assumption",
          .detail = "Folded " +
                    std::to_string(early_folded_constants.grd_angle_assumptions) +
                    " ГРД-only trigonometric identity node(s) under expected_mode(\"grd\").",
      });
    }
    if (const std::optional<core::emit::lowering::DecimalSeriesProgram> decimal_series =
            core::emit::lowering::match_decimal_series_program(*ast.v2)) {
      exact_decimal_series = true;
      (void)core::emit::lowering::lower_decimal_series_program(context.emitter, context.diagnostics,
                                                               *decimal_series);
      context.optimizations.push_back(OptimizationReport{
          .name = "decimal-series-lowering",
          .detail = "Lowered decimal recurrence to " + std::to_string(decimal_series->digits) +
                    "-digit MK-61 program.",
      });
      hoist_machine_item_blocks(context.emitter.items, context.emitter.items.size(),
                                context.emitter.items.size(), options.hoist_shared_helpers,
                                options.hoist_procs);
    } else {
      (void)core::fold_proved_packed_bcd_popcount_loops(*ast.v2, context.optimizations);
      pack_counter_stripes(*ast.v2, context.optimizations, false, std::nullopt);
      if (options.pack_counter_stripes) {
        const std::optional<std::vector<std::string>> requested_names =
            options.pack_counter_stripe_names.empty()
                ? std::nullopt
                : std::optional<std::vector<std::string>>{options.pack_counter_stripe_names};
        pack_counter_stripes(*ast.v2, context.optimizations, true, requested_names);
      }
      if (options.sentinel_decimal_pack) {
        const std::optional<std::vector<std::string>> requested_names =
            options.sentinel_decimal_pack_names.empty()
                ? std::nullopt
                : std::optional<std::vector<std::string>>{options.sentinel_decimal_pack_names};
        pack_sentinel_decimal_counters(*ast.v2, context.optimizations, requested_names);
      }
      if (options.trig_fractional_pack) {
        const std::optional<std::vector<std::string>> requested_names =
            options.trig_fractional_pack_names.empty()
                ? std::nullopt
                : std::optional<std::vector<std::string>>{options.trig_fractional_pack_names};
        pack_trig_fractional_counters(*ast.v2, context.optimizations, requested_names);
      }
      if (options.sign_pack_state) {
        sign_pack_state(*ast.v2, context.optimizations, options.sign_packed_state_plans,
                        options.sign_packed_state_plans.size() >= 2U ? "sign-pack-state-tuple"
                                                                     : "sign-pack-state");
      }
      resolve_constant_indexed_state(*ast.v2, context.optimizations);
      materialize_display_expressions(*ast.v2, context.optimizations,
                                      options.inline_floor_packed_row_expressions);
      elide_x_param_return_state_fields(*ast.v2, context.optimizations);
      index_constants(context, *ast.v2);
      const core::ConstantFoldResult folded_constants =
          core::fold_program_constants(*ast.v2, context.constants);
      if (folded_constants.applied > 0) {
        context.optimizations.push_back(OptimizationReport{
            .name = "expression-constant-folder",
            .detail = "Folded " + std::to_string(folded_constants.applied) +
                      " constant expression node" + (folded_constants.applied == 1 ? "" : "s") +
                      " before code generation.",
        });
      }
      if (folded_constants.grd_angle_assumptions > 0) {
        context.optimizations.push_back(OptimizationReport{
            .name = "grd-angle-mode-assumption",
            .detail = "Folded " + std::to_string(folded_constants.grd_angle_assumptions) +
                      " ГРД-only trigonometric identity node(s) under expected_mode(\"grd\").",
        });
      }
      if (!context.setup_only_counted_loop_init) {
        const int normalized_state_init_counted_loops = normalize_state_init_counted_loops(*ast.v2);
        if (normalized_state_init_counted_loops > 0) {
          context.optimizations.push_back(OptimizationReport{
              .name = "state-init-counted-loop",
              .detail = "Recovered the compact F Lx counted-loop lowering for " +
                        std::to_string(normalized_state_init_counted_loops) +
                        " state-initialized countdown counter" +
                        (normalized_state_init_counted_loops == 1 ? "." : "s."),
          });
        }
      }
      if (options.unroll_counted_loops)
        unroll_counted_loops(*ast.v2, context.optimizations);
      if (options.canonicalize_if_chains)
        canonicalize_constant_if_chains(*ast.v2, context.optimizations);
      if (options.comparison_guarded_update_selectors) {
        canonicalize_comparison_guarded_update_corrections(*ast.v2, context.optimizations);
        const core::ConstantFoldResult refolded_constants =
            core::fold_program_constants(*ast.v2, context.constants);
        if (refolded_constants.applied > 0) {
          context.optimizations.push_back(OptimizationReport{
              .name = "expression-constant-folder",
              .detail = "Folded " + std::to_string(refolded_constants.applied) +
                        " comparison guarded correction expression node" +
                        (refolded_constants.applied == 1 ? "" : "s") + " before code generation.",
          });
        }
        if (refolded_constants.grd_angle_assumptions > 0) {
          context.optimizations.push_back(OptimizationReport{
              .name = "grd-angle-mode-assumption",
              .detail = "Folded " + std::to_string(refolded_constants.grd_angle_assumptions) +
                        " ГРД-only trigonometric identity node(s) under expected_mode(\"grd\").",
          });
        }
      }
      inline_display_string_assignments(*ast.v2, context.optimizations);
      hoist_one_shot_loop_initializers(*ast.v2, context.optimizations);
      inline_single_use_constant_guarded_calls(*ast.v2, context.optimizations);
      inline_display_string_assignments(*ast.v2, context.optimizations);
      trim_display_edge_whitespace(*ast.v2, context.optimizations);
      fuse_tail_copy_assignments(*ast.v2, context.optimizations);
      if (options.dead_source_residual_temp_reuse)
        reuse_dead_source_residual_temps(*ast.v2, context.optimizations);
      inline_indexed_bit_report_branch_temps(*ast.v2, context.optimizations);
      resolve_constant_indexed_state(*ast.v2, context.optimizations);
      eliminate_unobserved_state(*ast.v2, context.optimizations);
      eliminate_identity_assignments(*ast.v2, context.optimizations);
      run_interprocedural_ast_passes(options, *ast.v2, context.optimizations);
      if (options.alternating_sign_toggle_args)
        toggle_alternating_literal_call_args(*ast.v2, context.optimizations);
      // TS performs dead-source residual temp reuse before common-tail hoisting.
      // Native currently lowers residual-temp reuse later, but the common-tail
      // pass must still run in this candidate so single-use tail inlining can
      // expose shared suffixes before code generation.
      hoist_common_branch_tails(*ast.v2, context.optimizations);
      if (options.guarded_prologue_gadgets)
        extract_guarded_prologue_gadgets(*ast.v2, context.optimizations);
      run_interprocedural_ast_passes(options, *ast.v2, context.optimizations);
      elide_terminal_loop_header_shows(*ast.v2, context.optimizations);
      if (!ast.v2->consts.empty()) {
        context.optimizations.push_back(OptimizationReport{
            .name = "const-inline",
            .detail = "Inlined " + std::to_string(ast.v2->consts.size()) +
                      " compile-time const declaration" + (ast.v2->consts.size() == 1 ? "." : "s."),
        });
      }
      const bool has_initial_state =
          std::any_of(ast.v2->state.begin(), ast.v2->state.end(), [](const V2StateField& field) {
            return field.initial.has_value() || field.initial_stack.has_value();
          });
      if (has_initial_state) {
        context.optimizations.push_back(OptimizationReport{
            .name = "auto-preload-initial-state",
            .detail = "Moved initial state into setup/preload values so official program cells "
                      "stay focused on turn logic.",
        });
      }
      context.optimizations.push_back(OptimizationReport{
          .name = "intent-domain-lowering",
          .detail = "Lowered " + std::to_string(ast.v2->state.size()) + " state fields and " +
                    std::to_string(ast.v2->rules.size()) +
                    " rules through the generic intent pipeline.",
      });
      eliminate_unreachable_v2_procs(*ast.v2, context.optimizations);
      if (options.canonicalize_repeated_unary_update_args) {
        canonicalize_repeated_unary_update_args(*ast.v2, context.optimizations);
      }
      if (options.x_param_value_functions) {
        elide_x_param_value_state_fields(*ast.v2, context.optimizations);
        materialize_x_param_value_function_scratch(*ast.v2, context.optimizations);
      }
      lift_function_calls_in_expressions(*ast.v2, context.optimizations,
                                         options.x_param_value_functions,
                                         options.stack_argument_function_entries);
      elide_loop_carried_prompt_state_fields(context, *ast.v2);
      warn_hardware_max_min_zero_operands(*ast.v2, context.diagnostics);
      std::set<std::string> loop_prompt_names;
      for (const auto& [name, unused_initial] : context.loop_prompt_initials) {
        (void)unused_initial;
        loop_prompt_names.insert(name);
      }
      if (!options.strict)
        warn_undeclared_allocations(*ast.v2, false, loop_prompt_names, context.diagnostics);
      warn_show_halt_style_rule(*ast.v2, result.warnings);
      context.transient_show_targets = transient_show_targets(*ast.v2);
      const bool can_attempt_lowering = !has_errors(context.diagnostics);
      if (can_attempt_lowering) {
        trace_stage("metadata-registers-preloads");
        trace_stage("metadata-index-program");
        index_program_metadata(context, *ast.v2);
        if (source_has_entered) {
          analyze_manual_interaction_protocols(context, *ast.v2);
          result.interaction_protocols = context.interaction_protocols;
        }
        trace_stage("metadata-display-counts");
        collect_literal_display_use_counts(context, *ast.v2);
        collect_packed_display_use_counts(context, *ast.v2);
        collect_show_sequence_use_counts(context, *ast.v2);
        collect_expression_use_counts(context, *ast.v2);
        trace_stage("metadata-index-rules");
        index_rules(context, *ast.v2);
        trace_stage("metadata-plan-stack-function-entries");
        plan_stack_argument_function_entries(context, *ast.v2);
        plan_stack_input_rule_entries(context, *ast.v2);
        if (context.indirect_underflow_decrement) {
          context.terminal_underflow_unit_decrements =
              collect_terminal_underflow_unit_decrements(context, *ast.v2);
        }
        trace_stage("metadata-collect-registers");
        const FeatureProfile lowering_profile = context.feature_profile;
        const bool forced_standard_rf_overflow =
            lowering_profile == FeatureProfile::Standard &&
            std::any_of(options.forced_register_shares.begin(),
                        options.forced_register_shares.end(), [](const RegisterShare& share) {
                          return share.free_register == "f";
                        });
        if (forced_standard_rf_overflow) {
          context.feature_profile = FeatureProfile::Mk61SMiniExpanded;
          context.standard_rf_overflow_allocation = true;
        }
        collect_registers(context, *ast.v2);
        trace_stage("metadata-forced-shares-preloads");
        context.preloaded_indirect_flow =
            context.preloaded_indirect_flow ||
            (program_uses_cells_bit_mask_sugar(context, *ast.v2) && !context.cave_sketch_shape);
        apply_forced_register_shares(context, options.forced_register_shares);
        if (forced_standard_rf_overflow) {
          const bool rf_remains =
              std::any_of(context.register_index_by_name.begin(),
                          context.register_index_by_name.end(), [](const auto& allocation) {
                            return allocation.second > core::k_max_register_index;
                          });
          context.feature_profile = lowering_profile;
          context.standard_rf_overflow_allocation = false;
          if (rf_remains) {
            context.diagnostics.push_back(diagnostic(
                DiagnosticSeverity::Error, "native-unsupported",
                "Register-lifetime proof did not eliminate the temporary Rf overflow color."));
          }
        }
        trace_stage("metadata-plan-constant-preloads");
        plan_general_constant_preloads(context, *ast.v2, options.startup_aware_constant_preloads,
                                       options.force_fractional_constant_selector_preloads);
        trace_stage("metadata-plan-spatial-preloads");
        plan_spatial_line_count_preloads(context, *ast.v2);
        trace_stage("metadata-near-any");
        collect_near_any_helper_stats(context, *ast.v2);
      }
      if (can_attempt_lowering) {
        trace_stage("lower-main-functions-helpers");
        const bool lowered_main = lower_statement_block(context, ast.v2->body);
        if (lowered_main) {
          clear_current_x_facts(context);
          const std::size_t main_end = context.emitter.items.size();
          bool emitted_tail = lower_function_rules(context, *ast.v2);
          const std::size_t function_end = context.emitter.items.size();
          if (emitted_tail && lower_terminal_tail_helpers(context) &&
              lower_packed_display_helpers(context) && lower_display_byte_helpers(context) &&
              lower_show_sequence_helpers(context) && lower_literal_display_helpers(context) &&
              lower_random_cell_helpers(context) && lower_expression_helpers(context) &&
              lower_grid_norm_helpers(context) &&
              lower_near_any_helpers(context) && lower_line_count_helpers(context) &&
              lower_spatial_line_progression_helpers(context) &&
              lower_spatial_sum_helpers(context) && lower_bit_mask_helper(context) &&
              lower_packed_bcd_helpers(context) &&
              lower_spatial_hit_helpers(context) && lower_packed_score_helper(context)) {
            emitted_tail = lower_segmented_bitplane_helpers(context);
          }
          if (emitted_tail) {
            hoist_machine_item_blocks(context.emitter.items, main_end, function_end,
                                      options.hoist_shared_helpers, options.hoist_procs);
          }
        }
      }
    }
  } catch (const std::exception& error) {
    context.diagnostics.push_back(
        diagnostic(DiagnosticSeverity::Error, "native-unsupported", error.what()));
  }

  if (context.constant_indexed_state_resolutions > 0) {
    context.optimizations.push_back(OptimizationReport{
        .name = "constant-indexed-state-resolution",
        .detail = "Resolved " + std::to_string(context.constant_indexed_state_resolutions) +
                  " constant indexed state access" +
                  (context.constant_indexed_state_resolutions == 1 ? "" : "es") +
                  " before pattern matching.",
    });
  }

  if (!has_errors(context.diagnostics) && ast.v2.has_value() &&
      options.collect_logical_register_allocation) {
    const std::optional<std::vector<LogicalRegisterAssignment>> assignment =
        solve_logical_register_allocation(context, *ast.v2, context.emitter.items);
    result.registers = context.registers;
    hide_internal_constant_report_registers(result.registers);
    hide_inline_x_param_report_registers(result.registers, context, *ast.v2);
    result.optimizations = context.optimizations;
    result.diagnostics.insert(result.diagnostics.end(), context.diagnostics.begin(),
                              context.diagnostics.end());
    if (!assignment.has_value()) {
      result.diagnostics.push_back(diagnostic(
          DiagnosticSeverity::Error, "native-unsupported",
          "Logical register interference graph requires more registers than the target profile."));
      result.implemented = false;
      return result;
    }
    result.logical_register_assignments = *assignment;
    result.implemented = true;
    return result;
  }

  if (!has_errors(context.diagnostics) && ast.v2.has_value() &&
      !options.forced_logical_register_assignments.empty()) {
    if (!verify_logical_register_allocation(context, *ast.v2, context.emitter.items)) {
      context.diagnostics.push_back(diagnostic(
          DiagnosticSeverity::Error, "native-unsupported",
          "Final logical register assignment failed the regenerated interference proof."));
    } else {
      context.optimizations.push_back(OptimizationReport{
          .name = "logical-register-lifetime-allocation",
          .detail = "Colored source-level register lifetimes and regenerated the program with "
                    "the proved physical assignment.",
      });
    }
  }

  CompileOptions pass_options = options;
  pass_options.preloaded_indirect_flow = context.preloaded_indirect_flow;
  if (options.aggressive_indirect_call)
    pass_options.aggressive_indirect_call_threshold = true;
  merge_planned_preloaded_constant_registers(pass_options, context);

  std::vector<MachineItem> ir_pass_input = context.emitter.items;
  std::map<std::string, std::string> pre_pass_coalesce_shares;
  if (!has_errors(context.diagnostics) && options.collect_coalesce_shares) {
    pre_pass_coalesce_shares = core::passes::compute_non_overlapping_register_mapping(
        raise_machine_to_ir(ir_pass_input, optimizer_feature_profile_for_options(options)),
        core::passes::RegisterCoalesceMappingOptions{
            .def_aware = true,
            .allow_live_at_entry_anchor_reuse = true,
        });
  }
  // Logical names are a lowering-time proof trace. Keeping them past the
  // regenerated-assignment check would leak an internal representation into
  // public IR JSON and could make unrelated post-lowering passes compare
  // proof annotations instead of executable machine semantics.
  for (MachineItem& item : ir_pass_input) {
    item.logical_register_name.reset();
    item.logical_indirect_memory_targets.reset();
  }
  std::vector<core::HelperSemanticContract> semantic_alias_contracts;
  if (!exact_decimal_series && ast.v2.has_value()) {
    semantic_alias_contracts = helper_semantic_alias_contracts(context, *ast.v2, ir_pass_input);
    if (options.analysis && !semantic_alias_contracts.empty()) {
      int certified_call_sites = 0;
      core::ExactIntegralDomain certified_domain;
      for (const core::HelperSemanticContract& contract : semantic_alias_contracts) {
        if (contract.admitted_call_origins.empty())
          continue;
        certified_call_sites += static_cast<int>(contract.admitted_call_origins.size());
        if (!certified_domain.valid()) {
          certified_domain = contract.admitted_input;
        } else {
          certified_domain.minimum =
              std::min(certified_domain.minimum, contract.admitted_input.minimum);
          certified_domain.maximum =
              std::max(certified_domain.maximum, contract.admitted_input.maximum);
        }
      }
      if (certified_call_sites > 0 && certified_domain.valid()) {
        context.optimizations.push_back(OptimizationReport{
            .name = "helper-semantic-alias-domain-proof",
            .detail = "Certified " + std::to_string(certified_call_sites) +
                      " direct helper call-site(s) with finite integral union [" +
                      std::to_string(certified_domain.minimum) + ", " +
                      std::to_string(certified_domain.maximum) + "]; issued " +
                      std::to_string(semantic_alias_contracts.size()) +
                      " typed semantic contract(s).",
        });
      }
    }
  }

  trace_stage("ir-passes");
  const core::passes::RunPassesResult optimized =
      exact_decimal_series ? core::passes::RunPassesResult{.items = ir_pass_input}
                           : core::passes::run_ir_passes(ir_pass_input, pass_options);
  result.registers = context.registers;
  hide_internal_constant_report_registers(result.registers);
  if (ast.v2.has_value())
    hide_inline_x_param_report_registers(result.registers, context, *ast.v2);
  result.optimizations = context.optimizations;
  for (const core::passes::AppliedOptimization& optimization : optimized.optimizations) {
    result.optimizations.push_back(OptimizationReport{
        .name = optimization.name,
        .detail = optimization.detail,
    });
  }
  result.diagnostics.insert(result.diagnostics.end(), context.diagnostics.begin(),
                            context.diagnostics.end());
  if (ast.v2.has_value() && has_register_allocation_failure(result.diagnostics) &&
      needs_random_unique_coord_list_setup_diagnostic(context, *ast.v2)) {
    result.diagnostics.push_back(diagnostic(
        DiagnosticSeverity::Error, "native-unsupported",
        "random_unique() coord_list setup needs contiguous list registers plus coord-list "
        "scratch registers."));
  }
  if (has_errors(result.diagnostics)) {
    result.implemented = false;
    return result;
  }

  trace_stage("post-layout");
  SingleUseProcedureInlineResult single_use_inline =
      inline_single_use_procedures(optimized.items);
  std::vector<MachineItem> post_layout_items = std::move(single_use_inline.items);
  std::vector<PreloadReport> layout_effective_preloads = optimized.preloads;
  std::vector<PreloadReport> setup_preloads;
  std::vector<PreloadReport> post_layout_flow_preloads;
  std::vector<PreloadReport> stop_tail_preloads;
  std::map<std::string, std::string> post_layout_preload_overrides;
  std::optional<std::vector<PreloadReport>> final_layout_effective_preloads;
  std::vector<core::passes::AppliedOptimization> post_layout_optimizations;
  const auto borrowed_entry_selector_registers_for = [](const std::vector<MachineItem>& items) {
    std::set<std::string> registers;
    for (const MachineItem& item : items) {
      if (item.kind != MachineItemKind::Op || !item.borrowed_entry_phase_selector)
        continue;
      const int family = item.opcode & 0xf0;
      const int register_index = item.opcode & 0x0f;
      const bool indirect_flow = family == 0x70 || family == 0x80 || family == 0x90 ||
                                 family == 0xa0 || family == 0xc0 || family == 0xe0;
      if (indirect_flow && register_index <= 14)
        registers.insert(core::register_name_for_index(register_index));
    }
    return registers;
  };
  if (single_use_inline.inlined > 0) {
    post_layout_optimizations.push_back(core::passes::AppliedOptimization{
        .name = "single-use-procedure-inline",
        .detail = "Inlined " + std::to_string(single_use_inline.inlined) +
                  " single-use procedure" + (single_use_inline.inlined == 1 ? "" : "s") +
                  " after proving a unique direct call and terminal return.",
    });
  }
  if (!exact_decimal_series) {
    const int indirect_flow_rescue_above =
        pass_options.aggressive_post_layout_indirect_flow
            ? 0
            : reference_indirect_flow_rescue_above(ast, options);
    bool return_stack_post_layout_changed = false;
    if (!options.disable_return_stack_script) {
      const std::size_t return_stack_budget =
          options.budget.has_value() && *options.budget > 0
              ? static_cast<std::size_t>(*options.budget)
              : program_step_limit_size_for_options(options);
      const bool return_stack_needs_size_rescue =
          core::machine_cell_count(post_layout_items) > static_cast<int>(return_stack_budget);
      const core::ReturnStackScriptOpportunityScan return_stack_script_scan =
          core::scan_return_stack_script_opportunity(post_layout_items, pass_options);
      const core::ReturnStackIrTailLayoutSearch return_stack_tail_layout_scan =
          core::analyze_return_stack_ir_tail_layout(
              raise_machine_to_ir(post_layout_items,
                                  optimizer_feature_profile_for_options(options)),
              core::ReturnStackStartupLayoutOptions{
                  .size_rescue = return_stack_needs_size_rescue,
                  .feature_profile = optimizer_feature_profile_for_options(options),
              });
      const bool profitable_tail_layout_signal =
          return_stack_tail_layout_scan.materialized &&
          (return_stack_tail_layout_scan.analysis.plan.profitable ||
           return_stack_needs_size_rescue);
      const bool run_return_stack_pipeline =
          options.return_stack_script || return_stack_script_scan.possible ||
          profitable_tail_layout_signal || return_stack_needs_size_rescue;
      if (run_return_stack_pipeline) {
      const core::ReturnStackIrTailLayoutSearch tail_layout =
          core::analyze_return_stack_ir_tail_layout_with_pipeline(
              raise_machine_to_ir(post_layout_items,
                                  optimizer_feature_profile_for_options(options)),
              post_layout_items, pass_options,
              core::ReturnStackStartupLayoutOptions{
                  .size_rescue = return_stack_needs_size_rescue,
                  .feature_profile = optimizer_feature_profile_for_options(options),
              },
              indirect_flow_rescue_above);
      if (tail_layout.materialized) {
        const core::ReturnStackStartupLayoutPlan& plan = tail_layout.analysis.plan;
        const bool layout_aware_profitable = tail_layout.pipeline_compared
                                                 ? tail_layout.pipeline_candidate_better
                                                 : core::compare_return_stack_post_layout_pipeline(
                                                       post_layout_items,
                                                       tail_layout.materialized_items,
                                                       pass_options,
                                                       indirect_flow_rescue_above)
                                                       .candidate_better;
        if (layout_aware_profitable) {
          post_layout_items = tail_layout.materialized_items;
          return_stack_post_layout_changed = true;
          std::string detail = std::string("Materialized ") + std::to_string(plan.transitions) +
                               " IR tail block" + (plan.transitions == 1 ? "" : "s") +
                               " as a proven ПП return-stack charge chain before post-layout rewrite";
          if (tail_layout.pipeline_compared) {
            detail += " after layout-aware full-pipeline comparison (candidate " +
                      std::to_string(tail_layout.pipeline_candidate_final_cells) +
                      " cells vs current " +
                      std::to_string(tail_layout.pipeline_current_final_cells) +
                      " cells after measuring " +
                      std::to_string(tail_layout.pipeline_candidates_measured) +
                      " materialized candidate" +
                      (tail_layout.pipeline_candidates_measured == 1 ? "" : "s") + ").";
          } else {
            detail += ".";
          }
          post_layout_optimizations.push_back(core::passes::AppliedOptimization{
              .name = "return-stack-startup-layout",
              .detail = std::move(detail),
          });
        } else if (options.return_stack_script && options.analysis) {
          std::string rejection = tail_layout.rejection_reason;
          if (rejection.empty()) {
            rejection = "return-stack startup layout materialized, but the full post-layout "
                        "pipeline was not smaller";
            if (tail_layout.pipeline_compared) {
              rejection += " (candidate " +
                           std::to_string(tail_layout.pipeline_candidate_final_cells) +
                           " cells vs current " +
                           std::to_string(tail_layout.pipeline_current_final_cells) + " cells)";
            }
          }
          result.diagnostics.push_back(diagnostic(
              DiagnosticSeverity::Note, "return-stack-layout-not-applied", rejection));
        }
      } else if (options.return_stack_script && options.analysis &&
                 !tail_layout.rejection_reason.empty()) {
        result.diagnostics.push_back(diagnostic(
            DiagnosticSeverity::Note, "return-stack-layout-not-applied",
            tail_layout.rejection_reason));
        if (tail_layout.rewritten_tail_fragments > 0) {
          std::string detail =
              "rewrote " + std::to_string(tail_layout.rewritten_tail_fragments) +
              " terminal IR tail suffix" +
              (tail_layout.rewritten_tail_fragments == 1 ? "" : "es") +
              " into " + std::to_string(tail_layout.extracted_tail_fragments) +
              " extracted fragment" +
              (tail_layout.extracted_tail_fragments == 1 ? "" : "s");
          if (tail_layout.reused_generated_tail_fragments > 0) {
            detail += ", reused " +
                      std::to_string(tail_layout.reused_generated_tail_fragments) +
                      " generated fragment" +
                      (tail_layout.reused_generated_tail_fragments == 1 ? "" : "s");
          }
          if (tail_layout.reused_existing_tail_fragments > 0) {
            detail += " and reused " +
                      std::to_string(tail_layout.reused_existing_tail_fragments) +
                      " existing whole-tail fragment" +
                      (tail_layout.reused_existing_tail_fragments == 1 ? "" : "s");
          }
          detail += " before profitability/layout proof";
          result.diagnostics.push_back(diagnostic(
              DiagnosticSeverity::Note, "return-stack-tail-fragments", detail));
          if (!tail_layout.materialized) {
            std::string nonterminal_labels;
            if (!tail_layout.cfg_tail_nonterminal_break_labels.empty()) {
              nonterminal_labels = "; first nonterminal break labels=";
              for (std::size_t index = 0;
                   index < tail_layout.cfg_tail_nonterminal_break_labels.size(); ++index) {
                if (index > 0)
                  nonterminal_labels += ",";
                nonterminal_labels += tail_layout.cfg_tail_nonterminal_break_labels.at(index);
              }
            }
            std::string external_entry_labels;
            if (!tail_layout.cfg_tail_external_entry_labels.empty()) {
              external_entry_labels = "; first external entry labels=";
              for (std::size_t index = 0;
                   index < tail_layout.cfg_tail_external_entry_labels.size(); ++index) {
                if (index > 0)
                  external_entry_labels += ",";
                external_entry_labels += tail_layout.cfg_tail_external_entry_labels.at(index);
              }
            }
            std::string external_predecessor_labels;
            if (!tail_layout.cfg_tail_external_predecessor_labels.empty()) {
              external_predecessor_labels = "; first external predecessor labels=";
              for (std::size_t index = 0;
                   index < tail_layout.cfg_tail_external_predecessor_labels.size(); ++index) {
                if (index > 0)
                  external_predecessor_labels += ",";
                external_predecessor_labels +=
                    tail_layout.cfg_tail_external_predecessor_labels.at(index);
              }
            }
            result.diagnostics.push_back(diagnostic(
                DiagnosticSeverity::Note, "return-stack-tail-fragment-chain-stats",
                "CFG tail-fragment chain scan considered " +
                    std::to_string(tail_layout.cfg_tail_entry_candidates) +
                    " terminal entry candidate" +
                    (tail_layout.cfg_tail_entry_candidates == 1 ? "" : "s") + ", found " +
                    std::to_string(tail_layout.cfg_tail_valid_chain_candidates) +
                    " 2..5-length chain candidate" +
                    (tail_layout.cfg_tail_valid_chain_candidates == 1 ? "" : "s") +
                    " (short=" +
                    std::to_string(tail_layout.cfg_tail_short_chain_candidates) +
                    ", too-long=" +
                    std::to_string(tail_layout.cfg_tail_too_long_chain_candidates) +
                    ", broken=" +
                    std::to_string(tail_layout.cfg_tail_broken_chain_candidates) +
                    " [unresolved=" +
                    std::to_string(tail_layout.cfg_tail_unresolved_chain_candidates) +
                    ", repeated=" +
                    std::to_string(tail_layout.cfg_tail_repeated_chain_candidates) +
                    ", nonterminal=" +
                    std::to_string(tail_layout.cfg_tail_nonterminal_chain_candidates) + "])" +
                    ", duplicated " +
                    std::to_string(tail_layout.cfg_tail_external_entry_duplications) +
                    " externally entered tail suffixes, rejected " +
                    std::to_string(tail_layout.cfg_tail_external_entry_rejections) +
                    " by external CFG entries" + nonterminal_labels +
                    external_entry_labels + external_predecessor_labels));
          }
        }
        if (tail_layout.extracted_existing_callsite_fragments > 0) {
          std::string detail =
              "extracted " +
              std::to_string(tail_layout.extracted_existing_callsite_fragments) +
              " terminal Call/ПП IR fragment" +
              (tail_layout.extracted_existing_callsite_fragments == 1 ? "" : "s");
          detail += " before existing-callsite proof";
          result.diagnostics.push_back(diagnostic(
              DiagnosticSeverity::Note, "return-stack-existing-callsite-fragments", detail));
        }
        if (tail_layout.symbolic_existing_callsite_hints > 0) {
          std::string target_labels;
          if (!tail_layout.symbolic_existing_callsite_target_labels.empty()) {
            target_labels = "; target labels=";
            for (std::size_t index = 0;
                 index < tail_layout.symbolic_existing_callsite_target_labels.size(); ++index) {
              if (index > 0)
                target_labels += ",";
              target_labels += tail_layout.symbolic_existing_callsite_target_labels.at(index);
            }
          }
          std::string target_group_details;
          if (!tail_layout.symbolic_existing_callsite_target_group_details.empty()) {
            target_group_details = "; target group details=";
            for (std::size_t index = 0;
                 index < tail_layout.symbolic_existing_callsite_target_group_details.size();
                 ++index) {
              if (index > 0)
                target_group_details += ",";
              target_group_details +=
                  tail_layout.symbolic_existing_callsite_target_group_details.at(index);
            }
          }
          std::string source_target_details;
          if (!tail_layout.symbolic_existing_callsite_source_target_details.empty()) {
            source_target_details = "; source target details=";
            for (std::size_t index = 0;
                 index < tail_layout.symbolic_existing_callsite_source_target_details.size();
                 ++index) {
              if (index > 0)
                source_target_details += ",";
              source_target_details +=
                  tail_layout.symbolic_existing_callsite_source_target_details.at(index);
            }
          }
          std::string source_labels;
          if (!tail_layout.symbolic_existing_callsite_source_labels.empty()) {
            source_labels = "; source labels=";
            for (std::size_t index = 0;
                 index < tail_layout.symbolic_existing_callsite_source_labels.size(); ++index) {
              if (index > 0)
                source_labels += ",";
              source_labels += tail_layout.symbolic_existing_callsite_source_labels.at(index);
            }
          }
          result.diagnostics.push_back(diagnostic(
              DiagnosticSeverity::Note, "return-stack-existing-callsite-hints",
              "found " + std::to_string(tail_layout.symbolic_existing_callsite_hints) +
                  " symbolic terminal Call/ПП hint" +
                  (tail_layout.symbolic_existing_callsite_hints == 1 ? "" : "s") +
                  "; target groups=" +
                  std::to_string(tail_layout.symbolic_existing_callsite_target_groups) +
                  ", largest group=" +
                  std::to_string(tail_layout.symbolic_existing_callsite_largest_target_group) +
                  target_labels + target_group_details + source_labels +
                  source_target_details +
                  "; counted as free charge sites only when a safe retargeting proof applies"));
        }
      }

      const core::PostLayoutIndirectFlowResult return_stack_script =
          core::optimize_post_layout_return_stack_script(post_layout_items, pass_options);
      post_layout_items = return_stack_script.items;
      post_layout_optimizations.insert(post_layout_optimizations.end(),
                                       return_stack_script.optimizations.begin(),
                                       return_stack_script.optimizations.end());
      if (return_stack_script.applied > 0)
        return_stack_post_layout_changed = true;
      if (return_stack_script.applied == 0) {
        const std::string rejection =
            core::explain_return_stack_script_rejection(post_layout_items, pass_options);
        if (options.return_stack_script && options.analysis && !rejection.empty()) {
          result.diagnostics.push_back(diagnostic(
              DiagnosticSeverity::Note, "return-stack-script-not-applied", rejection));
        }

        bool dirty_dispatch_proved = false;
        bool dirty_allocator_available = false;
        bool dirty_allocator_applied = false;
        core::DirtyReturnStackDispatchAllocationPlan best_dirty_allocation;
        int dirty_allocator_padding = 0;
        int dirty_allocator_append_padding = 0;
        int dirty_allocator_insert_padding = 0;
        int dirty_allocator_rounds = 0;
        std::string dirty_rejection;
        if (return_stack_needs_size_rescue) {
          const std::vector<core::DirtyReturnStackDispatchAllocationPlan> dirty_allocations =
              core::allocate_dirty_return_stack_dispatch_layouts(
                  post_layout_items,
                  core::DirtyReturnStackDispatchOptions{
                      .feature_profile = optimizer_feature_profile_for_options(options),
                      .size_rescue = true,
                  });
          auto overlay_flow_cell_count = [&](const std::vector<MachineItem>& items) {
            return core::measure_return_stack_downstream_post_layout_pipeline(
                       items, pass_options, indirect_flow_rescue_above)
                .final_cells;
          };
          std::optional<int> current_flow_cells;
          int best_candidate_flow_cells = 0;
          for (const core::DirtyReturnStackDispatchAllocationPlan& dirty_allocation :
               dirty_allocations) {
            if (dirty_allocation.allocated && dirty_allocation.dispatch.layout_proved) {
              dirty_dispatch_proved = true;
              if (dirty_allocation.padding_cells > 0) {
                dirty_allocator_available = true;
                if (!current_flow_cells.has_value())
                  current_flow_cells = overlay_flow_cell_count(post_layout_items);
                const int candidate_flow_cells = overlay_flow_cell_count(dirty_allocation.items);
                const bool better_candidate = !dirty_allocator_applied ||
                                              candidate_flow_cells < best_candidate_flow_cells ||
                                              (candidate_flow_cells == best_candidate_flow_cells &&
                                               (dirty_allocation.padding_cells <
                                                    best_dirty_allocation.padding_cells ||
                                                (dirty_allocation.padding_cells ==
                                                     best_dirty_allocation.padding_cells &&
                                                 dirty_allocation.insert_padding_cells <
                                                     best_dirty_allocation.insert_padding_cells)));
                if (candidate_flow_cells < *current_flow_cells && better_candidate) {
                  dirty_allocator_applied = true;
                  best_candidate_flow_cells = candidate_flow_cells;
                  best_dirty_allocation = dirty_allocation;
                }
                if (!dirty_allocator_applied &&
                    (dirty_allocator_padding == 0 ||
                     dirty_allocation.padding_cells < dirty_allocator_padding ||
                     (dirty_allocation.padding_cells == dirty_allocator_padding &&
                      dirty_allocation.insert_padding_cells < dirty_allocator_insert_padding))) {
                  dirty_allocator_padding = dirty_allocation.padding_cells;
                  dirty_allocator_append_padding = dirty_allocation.append_padding_cells;
                  dirty_allocator_insert_padding = dirty_allocation.insert_padding_cells;
                  dirty_allocator_rounds = dirty_allocation.fixed_point_rounds;
                }
              }
            }
            if (dirty_rejection.empty() && !dirty_allocation.rejection_reason.empty())
              dirty_rejection = dirty_allocation.rejection_reason;
          }
          if (dirty_allocator_applied) {
            dirty_allocator_padding = best_dirty_allocation.padding_cells;
            dirty_allocator_append_padding = best_dirty_allocation.append_padding_cells;
            dirty_allocator_insert_padding = best_dirty_allocation.insert_padding_cells;
            dirty_allocator_rounds = best_dirty_allocation.fixed_point_rounds;
          }
        } else {
          dirty_rejection =
              "dirty return-stack dispatch allocator is disabled outside size-rescue mode";
        }
        if (dirty_allocator_applied) {
          post_layout_items = best_dirty_allocation.items;
          return_stack_post_layout_changed = true;
          const std::string dirty_allocator_detail =
              "Applied dirty return-stack dispatch layout allocation with " +
              std::to_string(dirty_allocator_padding) + " executable cell" +
              (dirty_allocator_padding == 1 ? "" : "s") + " (" +
              std::to_string(dirty_allocator_append_padding) + " appended, " +
              std::to_string(dirty_allocator_insert_padding) + " inserted) after " +
              std::to_string(dirty_allocator_rounds) + " fixed-point round" +
              (dirty_allocator_rounds == 1 ? "" : "s") +
              " because the post-allocation overlay/indirect-flow pipeline is smaller.";
          post_layout_optimizations.push_back(core::passes::AppliedOptimization{
              .name = "return-stack-dirty-dispatch-allocator",
              .detail = dirty_allocator_detail,
          });
          if (options.analysis) {
            result.diagnostics.push_back(diagnostic(
                DiagnosticSeverity::Note, "return-stack-dirty-dispatch-allocator",
                dirty_allocator_detail));
          }
        } else if (options.return_stack_script && options.analysis && dirty_allocator_available) {
          const std::string dirty_allocator_detail =
              "Proved dirty return-stack dispatch layout allocation with " +
              std::to_string(dirty_allocator_padding) + " executable cell" +
              (dirty_allocator_padding == 1 ? "" : "s") + " (" +
              std::to_string(dirty_allocator_append_padding) + " appended, " +
              std::to_string(dirty_allocator_insert_padding) + " inserted) after " +
              std::to_string(dirty_allocator_rounds) + " fixed-point round" +
              (dirty_allocator_rounds == 1 ? "" : "s") +
              ", but did not apply it because the post-allocation overlay/indirect-flow pipeline was not smaller.";
          result.diagnostics.push_back(diagnostic(
              DiagnosticSeverity::Note, "return-stack-dirty-dispatch-allocator-not-applied",
              dirty_allocator_detail));
        } else if (options.return_stack_script && options.analysis && !dirty_dispatch_proved) {
          result.diagnostics.push_back(diagnostic(
              DiagnosticSeverity::Note, "return-stack-dirty-dispatch-not-applied",
              dirty_rejection.empty()
                  ? "dirty return-stack dispatch requires a layout with safe executable dirty "
                    "return target cells"
                  : dirty_rejection));
        }
      }
      } else if (options.return_stack_script && options.analysis) {
        result.diagnostics.push_back(diagnostic(
            DiagnosticSeverity::Note, "return-stack-script-not-applied",
            "return-stack pipeline found no proven charge-chain, tail-layout, or size-rescue "
            "opportunity in this layout"));
      }
    }

    if (return_stack_post_layout_changed) {
      const core::PostLayoutIndirectFlowResult post_layout_overlay =
          core::optimize_post_layout_address_code_overlay(post_layout_items, {}, pass_options);
      post_layout_items = post_layout_overlay.items;
      post_layout_optimizations.insert(post_layout_optimizations.end(),
                                       post_layout_overlay.optimizations.begin(),
                                       post_layout_overlay.optimizations.end());
    }

    // Expose identical call continuations before indirect-flow selectors make
    // cell deletion require preload retargeting. The ordinary late hoist below
    // remains the fallback for artifacts that already contain indirect flow.
    for (;;) {
      const std::optional<ProvedIndirectFlowSet> early_indirect_flow_proof =
          collect_proved_indirect_flow_set(
              post_layout_items, address_space_model_for_options(options));
      if (!early_indirect_flow_proof.has_value())
        break;
      const core::HelperInvariantRecallHoistResult early_recall_hoist =
          core::optimize_helper_invariant_recall_hoist(
              post_layout_items,
              core::HelperInvariantRecallHoistOptions{
                  .proved_indirect_flow_targets =
                      early_indirect_flow_proof->targets,
              });
      if (early_recall_hoist.applied <= 0 ||
          !early_recall_hoist.proof.final_artifact_proved ||
          !helper_hoist_preserves_fixed_indirect_targets(
              *early_indirect_flow_proof, early_recall_hoist.proof)) {
        break;
      }
      post_layout_items = early_recall_hoist.items;
      post_layout_optimizations.insert(post_layout_optimizations.end(),
                                       early_recall_hoist.optimizations.begin(),
                                       early_recall_hoist.optimizations.end());
    }

    // Before generic selector overlay turns direct calls into address-bearing
    // indirect commands, consider an atomic physical-00/F9 layout. Component
    // placement is size-neutral and source-agnostic; only the independently
    // proved removal of В/О@48 may make the transaction win.
    if (apply_final_layout_size_rescue && apply_atomic_absolute_dark_rescue &&
        core::machine_cell_count(post_layout_items) >
        program_step_limit_for_options(options)) {
      struct EarlyDarkLayoutCandidate {
        std::vector<MachineItem> items;
        std::vector<PreloadReport> preloads;
        std::vector<core::passes::AppliedOptimization> optimizations;
        std::string helper_label;
      };
      std::optional<EarlyDarkLayoutCandidate> best_dark_layout;
      std::vector<std::string> early_dark_rejections;
      const auto remember_dark_rejection = [&](std::string reason) {
        if (!options.analysis || reason.empty() ||
            early_dark_rejections.size() >= 12U ||
            std::find(early_dark_rejections.begin(), early_dark_rejections.end(),
                      reason) != early_dark_rejections.end()) {
          return;
        }
        early_dark_rejections.push_back(std::move(reason));
      };
      const int initial_cells = core::machine_cell_count(post_layout_items);
      const AddressSpaceModel model = address_space_model_for_options(options);
      const std::optional<std::vector<MachineItem>> normalized_dark_input =
          core::normalize_natural_target_overflow_formals(post_layout_items, model);
      if (normalized_dark_input.has_value()) {
        core::PostLayoutControlFlowOptions dark_control_options;
        dark_control_options.address_space_model = model;
        dark_control_options.empty_return_target = 1;
        const core::AuthoritativePostLayoutControlFlow dark_control =
            core::build_post_layout_control_flow(*normalized_dark_input,
                                                 dark_control_options);

        const auto consider_dark_layout_input =
            [&](const std::vector<MachineItem>& layout_input,
                const std::vector<PreloadReport>& layout_preloads,
                const core::AuthoritativePostLayoutControlFlow& layout_control,
                bool used_empty_return_startup) {
              if (!layout_control.proved)
                return;
              const std::vector<core::DarkSideSuffixLayoutCandidate> helpers =
                  core::find_dark_side_suffix_layout_candidates(layout_input, model);
              if (helpers.empty())
                remember_dark_rejection("no direct-call straight-line helper ending in В/О");
              const std::optional<std::vector<std::string>> late_bound_decimal_targets =
                  core::late_bound_decimal_selector_target_labels(layout_input);
              if (!late_bound_decimal_targets.has_value()) {
                remember_dark_rejection("malformed late-bound decimal selector marker");
                return;
              }
              for (const core::DarkSideSuffixLayoutCandidate& helper : helpers) {
                core::NaturalTargetComponentLayoutOptions layout_options;
                layout_options.address_space_model = model;
                layout_options.maximum_subset_states = 512;
                layout_options.maximum_anchors = options.maximum_natural_target_anchors;
                layout_options.required_absolute_targets.push_back(
                    core::NaturalTargetRequiredAbsoluteTarget{
                        .target_item = helper.target_item_index,
                        .target_address = helper.required_start_address,
                    });
                layout_options.allow_size_neutral_absolute_layout = true;
                layout_options.require_size_neutral_absolute_layout = true;
                layout_options.required_bounded_target_labels.assign(
                    late_bound_decimal_targets->begin(),
                    late_bound_decimal_targets->end());
                // Every such target after physical 48 moves back one when the
                // explicit return is removed. Address 100 is therefore the
                // exact pre-erasure upper bound for a final two-digit charge.
                layout_options.maximum_bounded_target_address = 100;
                layout_options.allow_size_neutral_bounded_layout = true;
                core::NaturalTargetComponentLayoutResult placed =
                    core::optimize_natural_target_component_layout(
                        layout_input, layout_preloads, layout_control,
                        layout_options);
                if (placed.applied <= 0 || !placed.plan.proved ||
                    !placed.plan.final_artifact_proved ||
                    !placed.plan.size_neutral_absolute_layout ||
                    !placed.plan.absolute_targets_proved ||
                    core::machine_cell_count(placed.items) !=
                        core::machine_cell_count(layout_input)) {
                  const std::string reason =
                      placed.plan.reasons.empty()
                          ? "absolute component placement was not proved"
                          : placed.plan.reasons.front();
                  remember_dark_rejection(helper.helper_label + ": " + reason);
                  continue;
                }
                std::optional<std::size_t> erased_return_item;
                int physical_address = 0;
                for (std::size_t item_index = 0; item_index < placed.items.size(); ++item_index) {
                  if (placed.items.at(item_index).kind == MachineItemKind::Label)
                    continue;
                  if (physical_address == 48) {
                    erased_return_item = item_index;
                    break;
                  }
                  ++physical_address;
                }
                if (!erased_return_item.has_value()) {
                  remember_dark_rejection(helper.helper_label +
                                           ": exact physical 48 cell is absent");
                  continue;
                }
                const core::PreloadedIndirectFlowCellErasurePlan selector_rebind =
                    core::plan_preloaded_indirect_flow_cell_erasure(
                        placed.items, placed.preloads,
                        placed.plan.final_control_flow, *erased_return_item, 48,
                        model);
                if (!selector_rebind.proved) {
                  const std::string reason =
                      selector_rebind.reasons.empty()
                          ? "indirect selector cell-erasure proof failed"
                          : selector_rebind.reasons.front();
                  remember_dark_rejection(helper.helper_label + ": " + reason);
                  continue;
                }
                core::DarkSideSuffixHelperOptions suffix_options;
                suffix_options.address_space_model = model;
                suffix_options.proved_indirect_flow_targets =
                    selector_rebind.original_targets;
                suffix_options.proved_rebound_indirect_flow_targets =
                    selector_rebind.rebound_targets;
                core::DarkSideSuffixHelperResult shortened =
                    core::rewrite_dark_side_suffix_helper(
                        placed.items, helper.helper_label, suffix_options);
                if (shortened.applied <= 0 || !shortened.proof.proved ||
                    !shortened.proof.final_artifact_proved) {
                  const std::string reason =
                      shortened.proof.reasons.empty()
                          ? "F9 suffix final-artifact proof failed"
                          : shortened.proof.reasons.front();
                  remember_dark_rejection(helper.helper_label + ": " + reason);
                  continue;
                }
                const core::LateBoundDecimalSelectorResult bounded_late_targets =
                    core::bind_late_bound_decimal_selectors(
                        shortened.items,
                        core::LateBoundDecimalSelectorOptions{
                            .minimum_target_address = 0,
                            .maximum_target_address = 99,
                        });
                if (!bounded_late_targets.diagnostics.empty()) {
                  remember_dark_rejection(
                      helper.helper_label +
                      ": final late-bound decimal target is outside 00..99");
                  continue;
                }
                const int shortened_cells =
                    core::machine_cell_count(shortened.items);
                if (shortened_cells >= initial_cells ||
                    (best_dark_layout.has_value() &&
                     shortened_cells >=
                         core::machine_cell_count(best_dark_layout->items))) {
                  continue;
                }
                std::vector<core::passes::AppliedOptimization> applied;
                if (used_empty_return_startup) {
                  applied.push_back(core::passes::AppliedOptimization{
                      .name = "empty-return-startup-layout",
                      .detail =
                          "Placed a transparent physical-00 return before an exact "
                          "absolute component layout and rechecked every runtime selector.",
                  });
                }
                applied.push_back(core::passes::AppliedOptimization{
                    .name = "absolute-component-layout",
                    .detail =
                        "Placed one opaque straight-line helper at physical " +
                        format_address(helper.required_start_address) +
                        " so its final body command is F9, without changing size or "
                        "command identity.",
                });
                applied.insert(applied.end(), shortened.optimizations.begin(),
                               shortened.optimizations.end());
                if (!selector_rebind.preload_rewrites.empty()) {
                  applied.push_back(core::passes::AppliedOptimization{
                      .name = "cell-erasure-indirect-selector-rebind",
                      .detail = "Retargeted " +
                                std::to_string(selector_rebind.preload_rewrites.size()) +
                                " proved stable indirect selector preload(s) after removing one "
                                "machine cell.",
                  });
                }
                best_dark_layout = EarlyDarkLayoutCandidate{
                    .items = std::move(shortened.items),
                    .preloads = selector_rebind.preloads,
                    .optimizations = std::move(applied),
                    .helper_label = helper.helper_label,
                };
              }
            };

        if (dark_control.proved && !normalized_dark_input->empty() &&
            normalized_dark_input->front().kind == MachineItemKind::Op &&
            normalized_dark_input->front().opcode == 0x52) {
          consider_dark_layout_input(*normalized_dark_input, layout_effective_preloads,
                                     dark_control, false);
        }
        if (dark_control.proved) {
          for (core::EmptyReturnStartupLayoutResult& startup :
               core::normalize_empty_return_startup_layouts(
                   *normalized_dark_input, layout_effective_preloads, dark_control,
                   core::TerminalCyclicLayoutOptions{
                       .address_space_model = model})) {
            if (startup.final_artifact_proved) {
              consider_dark_layout_input(startup.items, startup.preloads,
                                         startup.control_flow, true);
            }
          }
        }
      }
      if (best_dark_layout.has_value()) {
        post_layout_items = std::move(best_dark_layout->items);
        layout_effective_preloads = std::move(best_dark_layout->preloads);
        for (const PreloadReport& preload : layout_effective_preloads)
          post_layout_preload_overrides[preload.register_name] = preload.value;
        post_layout_optimizations.insert(
            post_layout_optimizations.end(),
            best_dark_layout->optimizations.begin(),
            best_dark_layout->optimizations.end());
      } else if (options.analysis) {
        if (!normalized_dark_input.has_value())
          remember_dark_rejection("overflow formal normalization failed");
        std::string detail =
            "No atomic empty-return/absolute-F9 helper layout reduced the artifact";
        for (std::size_t index = 0; index < early_dark_rejections.size(); ++index)
          detail += (index == 0U ? ": " : " | ") + early_dark_rejections.at(index);
        post_layout_optimizations.push_back(core::passes::AppliedOptimization{
            .name = "absolute-dark-side-layout-rejected",
            .detail = std::move(detail),
        });
      }
    }

    const core::PostLayoutIndirectFlowResult post_layout_flow =
        core::optimize_post_layout_super_dark_address_overlay(
            post_layout_items, pass_options, indirect_flow_rescue_above);
    post_layout_items = post_layout_flow.items;
    post_layout_flow_preloads = post_layout_flow.preloads;
    post_layout_optimizations.insert(post_layout_optimizations.end(),
                                     post_layout_flow.optimizations.begin(),
                                     post_layout_flow.optimizations.end());

    std::vector<PreloadReport> r0_existing_preloads = layout_effective_preloads;
    r0_existing_preloads.insert(r0_existing_preloads.end(), post_layout_flow.preloads.begin(),
                                post_layout_flow.preloads.end());
    const core::PostLayoutIndirectFlowResult post_layout_r0_flow =
        core::optimize_post_layout_fractional_r0_flow(post_layout_items, r0_existing_preloads,
                                                      pass_options);
    post_layout_items = post_layout_r0_flow.items;
    post_layout_optimizations.insert(post_layout_optimizations.end(),
                                     post_layout_r0_flow.optimizations.begin(),
                                     post_layout_r0_flow.optimizations.end());

    setup_preloads = build_preload_reports(context, *ast.v2, post_layout_items);
    for (PreloadReport& setup_preload : setup_preloads) {
      const auto rebound =
          post_layout_preload_overrides.find(setup_preload.register_name);
      if (rebound != post_layout_preload_overrides.end())
        setup_preload.value = rebound->second;
    }
    const std::set<std::string> borrowed_entry_selector_registers =
        borrowed_entry_selector_registers_for(post_layout_items);
    for (PreloadReport& setup_preload : setup_preloads) {
      if (!borrowed_entry_selector_registers.contains(setup_preload.register_name))
        continue;
      const auto selector =
          std::find_if(post_layout_flow_preloads.begin(), post_layout_flow_preloads.end(),
                       [&](const PreloadReport& preload) {
                         return preload.register_name == setup_preload.register_name;
                       });
      if (selector == post_layout_flow_preloads.end())
        continue;
      setup_preload.value = selector->value;
      post_layout_preload_overrides[setup_preload.register_name] = selector->value;
    }
    std::vector<PreloadReport> stop_tail_input = post_layout_flow.preloads;
    const std::vector<PreloadReport> retargetable_setup_preloads =
        fractional_selector_setup_preloads(setup_preloads, context);
    stop_tail_input.insert(stop_tail_input.end(), retargetable_setup_preloads.begin(),
                           retargetable_setup_preloads.end());
    const core::PostLayoutIndirectFlowResult post_layout_stop_tail =
        core::optimize_post_layout_stop_tail_reuse(post_layout_items, stop_tail_input,
                                                   pass_options);
    post_layout_items = post_layout_stop_tail.items;
    stop_tail_preloads = post_layout_stop_tail.preloads;
    post_layout_optimizations.insert(post_layout_optimizations.end(),
                                     post_layout_stop_tail.optimizations.begin(),
                                     post_layout_stop_tail.optimizations.end());

    std::vector<PreloadReport> overlay_preloads = post_layout_flow_preloads;
    for (const PreloadReport& preload : stop_tail_preloads) {
      const bool present = std::any_of(
          overlay_preloads.begin(), overlay_preloads.end(),
          [&](const PreloadReport& existing) {
            return existing.register_name == preload.register_name;
          });
      if (!present)
        overlay_preloads.push_back(preload);
    }
    const core::PostLayoutIndirectFlowResult post_layout_overlay =
        core::optimize_post_layout_address_code_overlay(post_layout_items, overlay_preloads,
                                                        pass_options);
    post_layout_items = post_layout_overlay.items;
    if (post_layout_overlay.applied > 0) {
      // The overlay deletes cells and shifts helper addresses; it returns the
      // preloaded indirect-flow selectors retargeted to the post-overlay layout.
      // Write the retargeted selector values back so the runtime preloads (R7,
      // etc.) dispatch to the shifted helper entries rather than one cell past
      // them (DEFECT 4 root cause).
      std::map<std::string, std::string> retargeted_by_register;
      for (const PreloadReport& preload : post_layout_overlay.preloads)
        retargeted_by_register[preload.register_name] = preload.value;
      auto apply_retarget = [&](std::vector<PreloadReport>& preloads) {
        for (PreloadReport& preload : preloads) {
          const auto it = retargeted_by_register.find(preload.register_name);
          if (it != retargeted_by_register.end())
            preload.value = it->second;
        }
      };
      apply_retarget(post_layout_flow_preloads);
      apply_retarget(stop_tail_preloads);
    }
    post_layout_optimizations.insert(post_layout_optimizations.end(),
                                     post_layout_overlay.optimizations.begin(),
                                     post_layout_overlay.optimizations.end());

    // Move a register value used identically around every direct call into the
    // root of the called straight-line helper.  The pass scans all labels and
    // accepts only a complete bounded stack/X2/CFG proof.  Existing indirect
    // control flow is supplied as a complete target set; already-materialized
    // numeric selectors must keep the same target after the deletion, while
    // label-derived dispatches are rebound by the late selector pass below.
    const std::optional<ProvedIndirectFlowSet> indirect_flow_proof =
        collect_proved_indirect_flow_set(post_layout_items,
                                         address_space_model_for_options(options));
    if (indirect_flow_proof.has_value()) {
      const core::HelperInvariantRecallHoistResult recall_hoist =
          core::optimize_helper_invariant_recall_hoist(
              post_layout_items,
              core::HelperInvariantRecallHoistOptions{
                  .proved_indirect_flow_targets = indirect_flow_proof->targets,
              });
      if (recall_hoist.applied > 0 && recall_hoist.proof.final_artifact_proved &&
          helper_hoist_preserves_fixed_indirect_targets(*indirect_flow_proof,
                                                        recall_hoist.proof)) {
        post_layout_items = recall_hoist.items;
        post_layout_optimizations.insert(post_layout_optimizations.end(),
                                         recall_hoist.optimizations.begin(),
                                         recall_hoist.optimizations.end());
      } else if (options.analysis && !recall_hoist.proof.reasons.empty()) {
        post_layout_optimizations.push_back(core::passes::AppliedOptimization{
            .name = "helper-invariant-recall-hoist-rejected",
            .detail = recall_hoist.proof.helper_label + ": " +
                      recall_hoist.proof.reasons.front(),
        });
      }
    }

    const std::optional<ProvedIndirectFlowSet> wrapper_indirect_flow_proof =
        collect_proved_indirect_flow_set(post_layout_items,
                                         address_space_model_for_options(options));
    if (wrapper_indirect_flow_proof.has_value()) {
      const std::vector<MachineItem> before_shared_helper_wrapper =
          post_layout_items;
      const core::SharedHelperWrapperResult shared_helper_wrapper =
          core::optimize_shared_helper_wrapper(
              post_layout_items,
              core::SharedHelperWrapperOptions{
                  .address_space_model = address_space_model_for_options(options),
                  .empty_return_target = 1,
                  .proved_indirect_flow_targets =
                      wrapper_indirect_flow_proof->targets,
              });
      const bool fixed_targets_preserved =
          shared_helper_wrapper.applied > 0 &&
          shared_helper_wrapper.proof.final_control_flow_proved &&
          shared_wrapper_preserves_fixed_indirect_targets(
              before_shared_helper_wrapper, *wrapper_indirect_flow_proof,
              shared_helper_wrapper.proof);
      if (fixed_targets_preserved) {
        post_layout_items = shared_helper_wrapper.items;
        post_layout_optimizations.insert(
            post_layout_optimizations.end(),
            shared_helper_wrapper.optimizations.begin(),
            shared_helper_wrapper.optimizations.end());
      } else if (options.analysis &&
                 !shared_helper_wrapper.proof.helper_label.empty() &&
                 (!shared_helper_wrapper.proof.reasons.empty() ||
                  shared_helper_wrapper.applied > 0)) {
        post_layout_optimizations.push_back(core::passes::AppliedOptimization{
            .name = "shared-helper-terminal-wrapper-rejected",
            .detail = [&] {
              std::string detail = shared_helper_wrapper.proof.helper_label + ": ";
              if (shared_helper_wrapper.applied > 0) {
                detail += "fixed numeric indirect-flow target changed identity or address";
              } else {
                detail += shared_helper_wrapper.proof.reasons.front();
              }
              return detail;
            }(),
        });
      }
    }

  } else {
    if (options.return_stack_script && options.analysis) {
      result.diagnostics.push_back(diagnostic(
          DiagnosticSeverity::Note, "return-stack-script-not-applied",
          "return-stack script is skipped for exact decimal-series lowering"));
    }
    setup_preloads = build_preload_reports(context, *ast.v2, post_layout_items);
  }

  // A one-cell-over-limit artifact may use the physical A4 -> 00 wrap as a
  // return only after the generic helper verifier has proved every entry and
  // relocation edge. The pass is deliberately profile- and layout-driven; it
  // has no source/program recognizer.
  const core::CyclicEndReturnResult cyclic_end_return =
      core::optimize_cyclic_end_return(
          post_layout_items,
          core::CyclicEndReturnOptions{
              .address_space_model = address_space_model_for_options(options)});
  if (cyclic_end_return.applied > 0) {
    post_layout_items = cyclic_end_return.items;
    post_layout_optimizations.insert(post_layout_optimizations.end(),
                                     cyclic_end_return.optimizations.begin(),
                                     cyclic_end_return.optimizations.end());
  }

  // This proof is intentionally run after every other layout-changing pass.
  // With no supplied indirect-target map it accepts only artifacts that contain
  // no indirect control flow, so an unknown selector can never be smuggled
  // across the deleted physical-48 return cell.
  const core::DarkSideSuffixHelperResult dark_side_suffix =
      core::optimize_dark_side_suffix_helper(
          post_layout_items,
          core::DarkSideSuffixHelperOptions{
              .address_space_model = address_space_model_for_options(options)});
  if (dark_side_suffix.applied > 0) {
    post_layout_items = dark_side_suffix.items;
    post_layout_optimizations.insert(post_layout_optimizations.end(),
                                     dark_side_suffix.optimizations.begin(),
                                     dark_side_suffix.optimizations.end());
  }

  if (final_layout_input_fingerprint != nullptr) {
    std::ostringstream fingerprint;
    const auto append_field = [&](std::string_view value) {
      fingerprint << value.size() << ':' << value;
    };
    const auto append_optional_string = [&](const std::optional<std::string>& value) {
      append_field(value.has_value() ? "1" : "0");
      if (value.has_value())
        append_field(*value);
    };
    const auto append_optional_int = [&](const std::optional<int>& value) {
      append_field(value.has_value() ? "1" : "0");
      if (value.has_value())
        append_field(std::to_string(*value));
    };
    const auto append_preloads = [&](const std::vector<PreloadReport>& preloads) {
      append_field(std::to_string(preloads.size()));
      for (const PreloadReport& preload : preloads) {
        append_field(preload.register_name);
        append_field(preload.value);
        append_field(preload.counts_against_program ? "1" : "0");
        append_optional_string(preload.retunable_natural_fractional_prefix);
        append_optional_string(preload.setup_target_name);
        append_field(preload.setup_expression ? "1" : "0");
        append_optional_string(preload.setup_expression_text);
        append_optional_int(preload.setup_source_line);
      }
    };

    append_field(machine_items_to_json(post_layout_items));
    append_preloads(setup_preloads);
    append_preloads(layout_effective_preloads);
    append_preloads(stop_tail_preloads);
    append_preloads(post_layout_flow_preloads);
    append_field(final_layout_effective_preloads.has_value() ? "1" : "0");
    if (final_layout_effective_preloads.has_value())
      append_preloads(*final_layout_effective_preloads);
    append_field(std::to_string(post_layout_preload_overrides.size()));
    for (const auto& [register_name, value] : post_layout_preload_overrides) {
      append_field(register_name);
      append_field(value);
    }
    append_field(std::to_string(context.registers.size()));
    for (const auto& [name, register_name] : context.registers) {
      append_field(name);
      append_field(register_name);
    }
    append_field(std::to_string(post_layout_optimizations.size()));
    // Details are diagnostics only; final-layout consumers branch on typed
    // optimization names and on MachineItem metadata serialized above.
    for (const core::passes::AppliedOptimization& optimization : post_layout_optimizations) {
      append_field(optimization.name);
    }
    append_field(std::to_string(options.maximum_natural_target_anchors));
    append_field(std::to_string(static_cast<int>(address_space_model_for_options(options))));
    append_field(options.analysis ? "1" : "0");
    *final_layout_input_fingerprint = std::move(fingerprint).str();
  }

  // A stable internal preload may already encode an address that can become a
  // shared helper's natural entry.  Reorder only fallthrough-closed components
  // and replace direct calls after an authoritative identity/return-stack
  // proof.  This is a size-rescue pass: programs that already fit keep their
  // established layout and listing.
  if (apply_final_layout_size_rescue &&
      address_space_model_for_options(options) == AddressSpaceModel::Standard &&
      core::machine_cell_count(post_layout_items) > program_step_limit_for_options(options) &&
      machine_supports(mk61_profile(), "return-empty-stack-jump")) {
    const auto preload_present = [](const std::vector<PreloadReport>& preloads,
                                    const std::string& register_name) {
      return std::any_of(preloads.begin(), preloads.end(), [&](const PreloadReport& preload) {
        return preload.register_name == register_name;
      });
    };
    const auto build_effective_preloads = [&](bool setup_program) {
      std::vector<PreloadReport> effective;
      const auto add_unique = [&](const PreloadReport& preload) {
        if (!preload_present(effective, preload.register_name))
          effective.push_back(preload);
      };
      for (const PreloadReport& preload : setup_preloads) {
        const bool selected =
            setup_program
                ? (preload_must_reach_generated_setup_program(preload) ||
                   !preload_present(stop_tail_preloads, preload.register_name))
                : (!preload_is_internal_collection_setup(preload) &&
                   !preload_present(stop_tail_preloads, preload.register_name));
        if (selected)
          add_unique(preload);
      }
      for (const PreloadReport& preload : layout_effective_preloads)
        add_unique(preload);
      for (const PreloadReport& preload : stop_tail_preloads)
        add_unique(preload);
      for (const PreloadReport& preload : post_layout_flow_preloads) {
        if (!preload_present(stop_tail_preloads, preload.register_name))
          add_unique(preload);
      }
      return effective;
    };
    const auto same_runtime_preload = [](const PreloadReport& left,
                                         const PreloadReport& right) {
      return left.register_name == right.register_name && left.value == right.value &&
             left.counts_against_program == right.counts_against_program &&
             left.retunable_natural_fractional_prefix ==
                 right.retunable_natural_fractional_prefix &&
             left.setup_target_name == right.setup_target_name &&
             left.setup_expression == right.setup_expression &&
             left.setup_expression_text == right.setup_expression_text &&
             left.setup_source_line == right.setup_source_line;
    };
    std::vector<PreloadReport> effective_preloads = build_effective_preloads(false);
    const std::vector<PreloadReport> setup_program_effective_preloads =
        build_effective_preloads(true);
    bool compatible_preloads =
        effective_preloads.size() == setup_program_effective_preloads.size();
    for (const PreloadReport& preload : effective_preloads) {
      const auto setup = std::find_if(
          setup_program_effective_preloads.begin(), setup_program_effective_preloads.end(),
          [&](const PreloadReport& candidate) {
            return candidate.register_name == preload.register_name;
          });
      if (setup == setup_program_effective_preloads.end() ||
          !same_runtime_preload(preload, *setup)) {
        compatible_preloads = false;
      }
    }

    if (compatible_preloads) {
      core::PostLayoutControlFlowOptions control_options;
      control_options.address_space_model = address_space_model_for_options(options);
      control_options.empty_return_target = 1;
      const std::optional<std::vector<MachineItem>> natural_layout_input =
          core::normalize_natural_target_overflow_formals(
              post_layout_items, address_space_model_for_options(options));
      core::AuthoritativePostLayoutControlFlow control_flow;
      if (natural_layout_input.has_value()) {
        control_flow =
            core::build_post_layout_control_flow(*natural_layout_input, control_options);
      }
      const bool has_late_bound_decimal_selector =
          std::any_of(post_layout_items.begin(), post_layout_items.end(),
                      [](const MachineItem& item) {
                        return std::any_of(
                            item.roles.begin(), item.roles.end(), [](const CellRole& role) {
                              return role.starts_with("late-decimal-selector-high:");
                            });
                      });
      if (options.analysis && has_late_bound_decimal_selector &&
          (!natural_layout_input.has_value() || !control_flow.proved)) {
        std::string detail = natural_layout_input.has_value()
                                 ? "authoritative control flow was not proved"
                                 : "overflow formal normalization failed";
        const std::size_t reason_count =
            std::min<std::size_t>(control_flow.reasons.size(), 8U);
        for (std::size_t reason = 0; reason < reason_count; ++reason)
          detail += (reason == 0U ? ": " : " | ") + control_flow.reasons.at(reason);
        result.diagnostics.push_back(diagnostic(
            DiagnosticSeverity::Note, "late-bound-natural-layout-control-rejected", detail));
      }
      if (natural_layout_input.has_value() && control_flow.proved) {
        std::set<std::string> late_bound_target_labels;
        constexpr std::string_view kLateBoundHighRole =
            "late-decimal-selector-high:";
        for (const MachineItem& item : *natural_layout_input) {
          for (const CellRole& role : item.roles) {
            if (role.starts_with(kLateBoundHighRole) &&
                role.size() > kLateBoundHighRole.size()) {
              late_bound_target_labels.insert(role.substr(kLateBoundHighRole.size()));
            }
          }
        }
        const core::NaturalTargetComponentLayoutOptions natural_options{
            .address_space_model = address_space_model_for_options(options),
            .maximum_anchors = options.maximum_natural_target_anchors,
            .maximum_rejection_reasons = options.analysis ? 512U : 0U,
            .required_bounded_target_labels =
                std::vector<std::string>(late_bound_target_labels.begin(),
                                         late_bound_target_labels.end()),
            .maximum_bounded_target_address = 99,
            .allow_size_neutral_bounded_layout = !late_bound_target_labels.empty(),
        };
        std::optional<core::NaturalTargetComponentLayoutResult> chosen_layout;
        std::optional<core::HelperSemanticAliasProof> chosen_alias;
        bool chosen_empty_return_startup = false;
        std::vector<std::string> natural_layout_search_rejections;
        const auto consider_layout = [&](core::NaturalTargetComponentLayoutResult candidate,
                                         std::optional<core::HelperSemanticAliasProof> alias,
                                         bool empty_return_startup = false) {
          if (options.analysis) {
            for (const std::string& reason : candidate.plan.reasons) {
              if (natural_layout_search_rejections.size() >= 512U)
                break;
              if (std::find(natural_layout_search_rejections.begin(),
                            natural_layout_search_rejections.end(), reason) ==
                  natural_layout_search_rejections.end()) {
                natural_layout_search_rejections.push_back(reason);
              }
            }
          }
          const int candidate_cells = core::machine_cell_count(candidate.items);
          const int current_cells = core::machine_cell_count(post_layout_items);
          const bool size_improves =
              candidate.removed_cells > 0 && candidate_cells < current_cells;
          const bool bounded_layout =
              candidate.plan.size_neutral_bounded_layout &&
              candidate.plan.bounded_targets_proved && candidate.removed_cells == 0 &&
              candidate_cells == current_cells;
          if (candidate.applied <= 0 || !candidate.plan.final_artifact_proved ||
              (!size_improves && !bounded_layout))
            return;
          if (!chosen_layout.has_value() || core::machine_cell_count(candidate.items) <
                                                core::machine_cell_count(chosen_layout->items)) {
            chosen_layout = std::move(candidate);
            chosen_alias = std::move(alias);
            chosen_empty_return_startup = empty_return_startup;
          }
        };

        core::NaturalTargetComponentLayoutResult ordinary_natural_layout =
            core::optimize_natural_target_component_layout(
                *natural_layout_input, effective_preloads, control_flow,
                natural_options);
        consider_layout(std::move(ordinary_natural_layout), std::nullopt);

        for (core::EmptyReturnStartupLayoutResult& startup :
             core::normalize_empty_return_startup_layouts(
                 *natural_layout_input, effective_preloads, control_flow,
                 core::TerminalCyclicLayoutOptions{
                     .address_space_model =
                         address_space_model_for_options(options)})) {
          if (!startup.final_artifact_proved)
            continue;
          consider_layout(core::optimize_natural_target_component_layout(
                              startup.items, startup.preloads,
                              startup.control_flow, natural_options),
                          std::nullopt, true);
        }

        const auto refreshed_contracts =
            refresh_helper_semantic_alias_contracts(*natural_layout_input,
                                                    semantic_alias_contracts);
        if (refreshed_contracts.has_value()) {
          core::HelperSemanticAliasOptions alias_options;
          alias_options.address_space_model = address_space_model_for_options(options);
          alias_options.main_entry = 0;
          alias_options.empty_return_target = 1;
          alias_options.effective_preloads = effective_preloads;
          alias_options.defer_preload_rebind = true;
          alias_options.identity_check_numeric_indirect_flow = true;
          const core::HelperSemanticAliasResult aliased = core::optimize_helper_semantic_alias(
              *natural_layout_input, *refreshed_contracts, alias_options);
          if (aliased.applied > 0 && aliased.proof.rewrite_proved &&
              aliased.proof.preload_rebind_deferred && aliased.proof.final_control_flow_proved &&
              core::machine_cell_count(aliased.items) <
                  core::machine_cell_count(*natural_layout_input)) {
            consider_layout(core::optimize_natural_target_component_layout(
                                aliased.items, effective_preloads, aliased.proof.final_control_flow,
                                natural_options),
                            aliased.proof);
          }
        }

        if (!chosen_layout.has_value() && options.analysis && has_late_bound_decimal_selector) {
          std::string detail = "no size-positive natural-target component layout was proved";
          const std::size_t reason_count =
              std::min<std::size_t>(natural_layout_search_rejections.size(), 8U);
          for (std::size_t reason = 0; reason < reason_count; ++reason)
            detail += (reason == 0U ? ": " : " | ") +
                      natural_layout_search_rejections.at(reason);
          result.diagnostics.push_back(diagnostic(
              DiagnosticSeverity::Note, "late-bound-natural-layout-plan-rejected", detail));
        }
        if (chosen_layout.has_value()) {
          core::NaturalTargetComponentLayoutResult& natural_layout = *chosen_layout;
          post_layout_items = natural_layout.items;
          final_layout_effective_preloads = natural_layout.preloads;
          for (const PreloadReport& preload : natural_layout.preloads)
            post_layout_preload_overrides[preload.register_name] = preload.value;
          const auto apply_preload_overrides = [&](std::vector<PreloadReport>& preloads) {
            for (PreloadReport& preload : preloads) {
              const auto found = post_layout_preload_overrides.find(preload.register_name);
              if (found != post_layout_preload_overrides.end())
                preload.value = found->second;
            }
          };
          apply_preload_overrides(setup_preloads);
          apply_preload_overrides(stop_tail_preloads);
          apply_preload_overrides(post_layout_flow_preloads);
          remove_preloaded_indirect_flow_comment_annotations(post_layout_items);
          if (chosen_alias.has_value()) {
            post_layout_optimizations.push_back(core::passes::AppliedOptimization{
                .name = "helper-semantic-alias",
                .detail = "Redirected " + std::to_string(chosen_alias->calls.size()) +
                          " complete physical call edge(s), carrying all " +
                          std::to_string(chosen_alias->source_call_origins) +
                          " opaque source-call origin(s), and removed a redundant " +
                          std::to_string(chosen_alias->removed_body_cells) +
                          "-cell unary-X helper before atomic downstream preload/layout "
                          "rebinding and final-artifact proof.",
            });
          }
          if (chosen_empty_return_startup) {
            post_layout_optimizations.push_back(core::passes::AppliedOptimization{
                .name = "empty-return-startup-layout",
                .detail =
                    "Placed a transparent physical-00 return before generic component "
                    "layout, retargeting only compiler-proved fractional selector "
                    "families and rechecking the complete final artifact.",
            });
          }
          std::vector<std::pair<std::string, int>> natural_placements;
          for (const core::NaturalTargetFlowRewrite& flow : natural_layout.plan.flows) {
            const std::pair<std::string, int> placement{
                flow.selector_register, flow.target_address};
            if (std::find(natural_placements.begin(), natural_placements.end(), placement) ==
                natural_placements.end()) {
              natural_placements.push_back(placement);
            }
          }
          std::string natural_layout_detail;
          if (natural_layout.plan.size_neutral_bounded_layout) {
            natural_layout_detail =
                "Reordered " + std::to_string(natural_layout.plan.moved_segments) +
                " fallthrough-closed component(s) without changing size so " +
                std::to_string(natural_layout.plan.bounded_targets) +
                " late-bound decimal selector target(s) fit in addresses 00..99 under "
                "the final-artifact identity/control/return-stack/stack/X2 proof.";
          } else if (natural_placements.size() == 1U) {
            natural_layout_detail =
                "Placed a proved helper at stable natural target " +
                format_address(natural_placements.front().second) + " through R" +
                natural_placements.front().first;
          } else {
            natural_layout_detail = "Placed " +
                                    std::to_string(natural_placements.size()) +
                                    " proved helpers at stable natural targets (";
            for (std::size_t index = 0; index < natural_placements.size(); ++index) {
              if (index != 0U)
                natural_layout_detail += ", ";
              natural_layout_detail += "R" + natural_placements.at(index).first + "->" +
                                       format_address(natural_placements.at(index).second);
            }
            natural_layout_detail += ")";
          }
          if (!natural_layout.plan.size_neutral_bounded_layout) {
          const int natural_calls = static_cast<int>(std::count_if(
              natural_layout.plan.flows.begin(), natural_layout.plan.flows.end(),
              [](const core::NaturalTargetFlowRewrite& flow) {
                return flow.original_opcode == 0x53;
              }));
          const int natural_jumps = static_cast<int>(std::count_if(
              natural_layout.plan.flows.begin(), natural_layout.plan.flows.end(),
              [](const core::NaturalTargetFlowRewrite& flow) {
                return flow.original_opcode == 0x51;
              }));
          const int natural_conditionals =
              natural_layout.applied - natural_calls - natural_jumps;
          natural_layout_detail +=
              " and replaced " + std::to_string(natural_layout.applied) +
              " direct flow command(s) with one-cell indirect flow (" +
              std::to_string(natural_calls) + " call(s), " +
              std::to_string(natural_jumps) + " jump(s), " +
              std::to_string(natural_conditionals) + " conditional(s))";
          const int alignment_cells =
              natural_layout.applied -
              natural_layout.plan.rebound_indirect_flows -
              2 * natural_layout.plan.transparent_trampolines -
              2 * natural_layout.plan.transparent_split_bridges -
              natural_layout.removed_cells;
          if (natural_layout.plan.rebound_indirect_flows > 0) {
            natural_layout_detail += " after reassigning " +
                                     std::to_string(
                                         natural_layout.plan.rebound_indirect_flows) +
                                     " address-only selector flow(s) back to direct form";
          }
          if (alignment_cells > 0) {
            natural_layout_detail += " while spending " +
                                     std::to_string(alignment_cells) +
                                     " proof-isolated unreachable alignment cell(s)";
          }
          if (natural_layout.plan.transparent_trampolines > 0) {
            natural_layout_detail += " through " +
                                     std::to_string(
                                         natural_layout.plan.transparent_trampolines) +
                                     " proved two-cell call trampoline(s)";
          }
          if (natural_layout.plan.transparent_split_bridges > 0) {
            natural_layout_detail += " with " +
                                     std::to_string(
                                         natural_layout.plan.transparent_split_bridges) +
                                     " proved fallthrough split bridge(s)";
          }
          natural_layout_detail += " after exact final-artifact "
              "control/return-stack/stack/X2/runtime-selector proofs.";
          }
          post_layout_optimizations.push_back(core::passes::AppliedOptimization{
              .name = natural_layout.plan.size_neutral_bounded_layout
                          ? "late-bound-decimal-target-layout"
                          : "natural-target-component-layout",
              .detail = std::move(natural_layout_detail),
          });
          if (natural_layout.plan.terminal_shared_return_folds > 0) {
            post_layout_optimizations.push_back(core::passes::AppliedOptimization{
                .name = "terminal-shared-return-selector-layout",
                .detail =
                    "Folded a proved terminal/direct-return branch through a stable "
                    "selector before generic component layout, then removed its "
                    "temporary final layout anchor after complete final-artifact proof.",
            });
          }
          if (options.analysis && !natural_layout_search_rejections.empty()) {
            std::string rejection_detail;
            for (const std::string& reason : natural_layout_search_rejections) {
              if (!rejection_detail.empty())
                rejection_detail += " | ";
              rejection_detail += reason;
            }
            post_layout_optimizations.push_back(core::passes::AppliedOptimization{
                .name = "natural-target-layout-rejections",
                .detail = std::move(rejection_detail),
            });
          }
        }
      }
    }
  }

  if (!exact_decimal_series) {
    std::vector<PreloadReport> terminal_layout_preloads;
    std::set<std::string> conflicting_terminal_preloads;
    const auto merge_terminal_preloads = [&](const std::vector<PreloadReport>& preloads) {
      for (const PreloadReport& preload : preloads) {
        if (conflicting_terminal_preloads.contains(preload.register_name))
          continue;
        const auto existing = std::find_if(
            terminal_layout_preloads.begin(), terminal_layout_preloads.end(),
            [&](const PreloadReport& candidate) {
              return candidate.register_name == preload.register_name;
            });
        if (existing == terminal_layout_preloads.end()) {
          terminal_layout_preloads.push_back(preload);
        } else if (existing->value != preload.value) {
          terminal_layout_preloads.erase(existing);
          conflicting_terminal_preloads.insert(preload.register_name);
        }
      }
    };
    merge_terminal_preloads(setup_preloads);
    merge_terminal_preloads(stop_tail_preloads);
    merge_terminal_preloads(final_layout_effective_preloads.has_value()
                                ? *final_layout_effective_preloads
                                : post_layout_flow_preloads);

    const bool shared_return_already_folded = std::any_of(
        post_layout_optimizations.begin(), post_layout_optimizations.end(),
        [](const core::passes::AppliedOptimization& optimization) {
          return optimization.name == "terminal-shared-return-selector-layout";
        });
    if (!shared_return_already_folded &&
        address_space_model_for_options(options) == AddressSpaceModel::Standard &&
        core::machine_cell_count(post_layout_items) >
            program_step_limit_for_options(options)) {
      core::PostLayoutControlFlowOptions shared_return_flow_options;
      shared_return_flow_options.address_space_model =
          address_space_model_for_options(options);
      shared_return_flow_options.empty_return_target = 1;
      const std::optional<std::vector<MachineItem>> shared_return_input =
          core::normalize_natural_target_overflow_formals(
              post_layout_items, address_space_model_for_options(options));
      if (shared_return_input.has_value()) {
        const core::AuthoritativePostLayoutControlFlow shared_return_flow =
            core::build_post_layout_control_flow(*shared_return_input,
                                                 shared_return_flow_options);
        if (shared_return_flow.proved) {
          const core::NaturalTargetComponentLayoutResult shared_return_layout =
              core::optimize_terminal_shared_return_selector_layout(
                  *shared_return_input, terminal_layout_preloads,
                  shared_return_flow,
                  core::NaturalTargetComponentLayoutOptions{
                      .address_space_model =
                          address_space_model_for_options(options),
                      .maximum_anchors = options.maximum_natural_target_anchors,
                      .maximum_rejection_reasons = options.analysis ? 512U : 0U,
                  },
                  core::TerminalCyclicLayoutOptions{
                      .address_space_model =
                          address_space_model_for_options(options),
                      .enable_return_alias = true,
                  });
          if (shared_return_layout.applied > 0 &&
              shared_return_layout.plan.proved &&
              shared_return_layout.plan.final_artifact_proved &&
              core::machine_cell_count(shared_return_layout.items) <
                  core::machine_cell_count(post_layout_items)) {
            post_layout_items = shared_return_layout.items;
            terminal_layout_preloads = shared_return_layout.preloads;
            final_layout_effective_preloads = shared_return_layout.preloads;
            for (const PreloadReport& preload : shared_return_layout.preloads)
              post_layout_preload_overrides[preload.register_name] = preload.value;
            const auto apply_shared_return_preloads =
                [&](std::vector<PreloadReport>& preloads) {
              for (PreloadReport& preload : preloads) {
                const auto found =
                    post_layout_preload_overrides.find(preload.register_name);
                if (found != post_layout_preload_overrides.end())
                  preload.value = found->second;
              }
            };
            apply_shared_return_preloads(setup_preloads);
            apply_shared_return_preloads(stop_tail_preloads);
            apply_shared_return_preloads(post_layout_flow_preloads);
            remove_preloaded_indirect_flow_comment_annotations(post_layout_items);
            post_layout_optimizations.push_back(core::passes::AppliedOptimization{
                .name = "terminal-shared-return-selector-layout",
                .detail =
                    "Reassigned one stable selector through the generic natural-target "
                    "solver and folded a proved terminal conditional/jump pair into one "
                    "indirect conditional after complete final-artifact proof.",
            });
          } else if (options.analysis) {
            std::string detail;
            const std::size_t reason_count =
                std::min<std::size_t>(shared_return_layout.plan.reasons.size(), 8U);
            for (std::size_t reason = 0; reason < reason_count; ++reason) {
              if (!detail.empty())
                detail += " | ";
              detail += shared_return_layout.plan.reasons.at(reason);
            }
            if (!detail.empty()) {
              post_layout_optimizations.push_back(
                  core::passes::AppliedOptimization{
                      .name = "terminal-shared-return-selector-rejections",
                      .detail = std::move(detail),
                  });
            }
          }
        }
      }
    }

    core::PostLayoutControlFlowOptions terminal_flow_options;
    terminal_flow_options.address_space_model = address_space_model_for_options(options);
    terminal_flow_options.empty_return_target = 1;
    const std::optional<std::vector<MachineItem>> normalized_terminal_input =
        core::normalize_natural_target_overflow_formals(
            post_layout_items, address_space_model_for_options(options));
    const std::vector<MachineItem>& normalized_terminal_items =
        normalized_terminal_input.has_value() ? *normalized_terminal_input : post_layout_items;
    const std::optional<std::vector<MachineItem>> symbolized_terminal_input =
        core::symbolize_terminal_layout_direct_targets(
            normalized_terminal_items, address_space_model_for_options(options));
    const std::vector<MachineItem>& terminal_input_items =
        symbolized_terminal_input.has_value() ? *symbolized_terminal_input
                                              : normalized_terminal_items;
    std::vector<core::HelperSemanticContract> terminal_semantic_contracts;
    for (const core::HelperSemanticContract& contract : semantic_alias_contracts) {
      const auto refreshed =
          refresh_helper_semantic_alias_contracts(terminal_input_items, {contract});
      if (refreshed.has_value() && refreshed->size() == 1U)
        terminal_semantic_contracts.push_back(refreshed->front());
    }
    const core::AuthoritativePostLayoutControlFlow terminal_input_flow =
        core::build_post_layout_control_flow(terminal_input_items, terminal_flow_options);
    if (terminal_input_flow.proved) {
      const core::TerminalCyclicLayoutResult terminal_layout =
          core::optimize_terminal_cyclic_layout(
              terminal_input_items, terminal_layout_preloads, terminal_input_flow,
              core::TerminalCyclicLayoutOptions{
                  .address_space_model = address_space_model_for_options(options),
                  .enable_return_alias = true,
                  .helper_semantic_contracts = &terminal_semantic_contracts});
      if (terminal_layout.applied > 0 && terminal_layout.plan.final_artifact_proved) {
        auto terminal_rebind_options = pass_options;
        for (const PreloadReport& preload : terminal_layout.preloads)
          terminal_rebind_options.preloaded_constant_registers[preload.register_name] =
              preload.value;
        const core::PostLayoutIndirectFlowResult rebound_flow =
            core::optimize_post_layout_indirect_flow(terminal_layout.items,
                                                     terminal_rebind_options, 0);
        std::vector<PreloadReport> rebound_preloads = terminal_layout.preloads;
        for (const PreloadReport& preload : rebound_flow.preloads) {
          const auto existing = std::find_if(
              rebound_preloads.begin(), rebound_preloads.end(),
              [&](const PreloadReport& candidate) {
                return candidate.register_name == preload.register_name;
              });
          if (existing == rebound_preloads.end())
            rebound_preloads.push_back(preload);
          else
            *existing = preload;
        }
        const core::AuthoritativePostLayoutControlFlow rebound_control =
            core::build_post_layout_control_flow(rebound_flow.items, terminal_flow_options);
        bool selectors_rebound = rebound_control.proved;
        constexpr std::string_view register_names = "0123456789abcde";
        for (const auto& [flow_source, targets] : rebound_control.indirect_flow_targets) {
          if (!selectors_rebound || flow_source >= rebound_flow.items.size() ||
              targets.size() != 1U) {
            selectors_rebound = false;
            break;
          }
          const int opcode = rebound_flow.items.at(flow_source).opcode;
          int register_index = opcode & 0x0f;
          if (register_index == 0x0f)
            register_index = 0;
          if (register_index < 0 ||
              register_index >= static_cast<int>(register_names.size())) {
            selectors_rebound = false;
            break;
          }
          const std::string register_name(
              1, register_names.at(static_cast<std::size_t>(register_index)));
          const auto preload = std::find_if(
              rebound_preloads.begin(), rebound_preloads.end(),
              [&](const PreloadReport& candidate) {
                return candidate.register_name == register_name;
              });
          if (preload == rebound_preloads.end()) {
            selectors_rebound = false;
            break;
          }
          const std::optional<core::IndirectAddressEvaluation> decoded =
              core::evaluate_indirect_address(
                  register_name, preload->value, core::IndirectOperationKind::Flow,
                  address_space_model_for_options(options));
          if (!decoded.has_value() || !decoded->actual_flow_target.has_value() ||
              *decoded->actual_flow_target != targets.front().address) {
            selectors_rebound = false;
            break;
          }
        }
        if (selectors_rebound &&
            core::machine_cell_count(rebound_flow.items) <
                core::machine_cell_count(post_layout_items)) {
          post_layout_items = rebound_flow.items;
          post_layout_flow_preloads = rebound_preloads;
          final_layout_effective_preloads = rebound_preloads;
          std::map<std::string, std::string> rebound_by_register;
          for (const PreloadReport& preload : rebound_preloads)
            rebound_by_register[preload.register_name] = preload.value;
          const auto apply_rebound_preloads = [&](std::vector<PreloadReport>& preloads) {
            for (PreloadReport& preload : preloads) {
              const auto rebound = rebound_by_register.find(preload.register_name);
              if (rebound != rebound_by_register.end())
                preload.value = rebound->second;
            }
          };
          apply_rebound_preloads(setup_preloads);
          apply_rebound_preloads(stop_tail_preloads);
          apply_rebound_preloads(post_layout_flow_preloads);
          for (const auto& [register_name, value] : rebound_by_register)
            post_layout_preload_overrides[register_name] = value;
          post_layout_optimizations.insert(post_layout_optimizations.end(),
                                           rebound_flow.optimizations.begin(),
                                           rebound_flow.optimizations.end());
          post_layout_optimizations.push_back(core::passes::AppliedOptimization{
              .name = terminal_layout.plan.semantic_return_alias_proved
                          ? "terminal-semantic-return-alias"
                          : terminal_layout.plan.return_alias_proved
                                ? "terminal-return-alias"
                                : "terminal-cyclic-layout",
              .detail = terminal_layout.plan.semantic_return_alias_proved
                            ? "Removed one direct conditional address cell after proving a "
                              "typed zero-domain helper return, stack ABI compatibility, and "
                              "complete continuation convergence."
                            : terminal_layout.plan.return_alias_proved
                                  ? "Removed one direct conditional address cell after proving "
                                    "an equivalent relocated return target."
                                  : "Removed " +
                                  std::to_string(terminal_layout.removed_cells) +
                                  " cell(s) after proving a generic terminal report tail" +
                                  (terminal_layout.plan.cyclic_proved
                                       ? " and its physical A4-to-00 cyclic return."
                                       : "."),
          });
        }
      } else if (options.analysis && !terminal_layout.plan.reasons.empty()) {
        std::string rejection_detail;
        const std::size_t reason_count =
            std::min<std::size_t>(terminal_layout.plan.reasons.size(), 8U);
        for (std::size_t reason = 0; reason < reason_count; ++reason) {
          if (!rejection_detail.empty())
            rejection_detail += " | ";
          rejection_detail += terminal_layout.plan.reasons.at(reason);
        }
        post_layout_optimizations.push_back(core::passes::AppliedOptimization{
            .name = "terminal-cyclic-layout-rejected",
            .detail = std::move(rejection_detail),
        });
      }
    }
  }

  // Bind symbolic decimal selector charges only after every procedure and
  // terminal-layout transformation has selected the delivered order.  In
  // particular, callee-hole leaves may begin outside the two-digit address
  // range and move into it during the final generic layout search.
  const core::LateBoundDecimalSelectorResult late_bound_selectors =
      core::bind_late_bound_decimal_selectors(
          post_layout_items,
          core::LateBoundDecimalSelectorOptions{.minimum_target_address = 0,
                                                .maximum_target_address = 99});
  post_layout_items = late_bound_selectors.items;
  result.diagnostics.insert(result.diagnostics.end(), late_bound_selectors.diagnostics.begin(),
                            late_bound_selectors.diagnostics.end());

  constexpr std::string_view kCalleeHoleLateChargeMarker =
      "callee-hole late-selector-label=";
  constexpr std::string_view kCalleeHoleLateLeavesMarker = "; leaf-labels=";
  constexpr std::string_view kCalleeHoleDeadScopeSuffix = "; selector-scope=dead";
  std::map<std::string, int> late_bound_target_by_label;
  for (const core::LateBoundDecimalSelectorProof& proof : late_bound_selectors.proofs) {
    late_bound_target_by_label[proof.target_label] = proof.target_address;
    const auto is_callee_hole_charge = [&](std::size_t item_index) {
      return item_index < post_layout_items.size() &&
             post_layout_items.at(item_index).comment.has_value() &&
             post_layout_items.at(item_index).comment->starts_with(
                 std::string(kCalleeHoleLateChargeMarker) + proof.target_label);
    };
    const bool callee_hole_charge = is_callee_hole_charge(proof.high_item_index) &&
                                    is_callee_hole_charge(proof.low_item_index);
    if (callee_hole_charge) {
      const bool dead_scope =
          post_layout_items.at(proof.high_item_index).comment->find(
              kCalleeHoleDeadScopeSuffix) != std::string::npos;
      const std::string proof_comment =
          "callee-hole selector-value=" + std::to_string(proof.target_address) +
          " indirect-target=" + std::to_string(proof.target_address) +
          (dead_scope ? std::string(kCalleeHoleDeadScopeSuffix) : "");
      post_layout_items.at(proof.high_item_index).comment = proof_comment;
      post_layout_items.at(proof.low_item_index).comment = proof_comment;
      for (std::size_t item_index = proof.low_item_index + 1U;
           item_index < post_layout_items.size(); ++item_index) {
        MachineItem& item = post_layout_items.at(item_index);
        if (!item.comment.has_value() ||
            !item.comment->starts_with(std::string(kCalleeHoleLateChargeMarker) +
                                       proof.target_label)) {
          continue;
        }
        item.comment = proof_comment;
        break;
      }
      continue;
    }

    for (const std::size_t item_index : {proof.high_item_index, proof.low_item_index}) {
      if (item_index >= post_layout_items.size())
        continue;
      MachineItem& item = post_layout_items.at(item_index);
      const std::string proof_comment =
          "late-bound-target=" + std::to_string(proof.target_address);
      item.comment = item.comment.has_value() ? *item.comment + "; " + proof_comment
                                              : proof_comment;
    }
  }

  bool unresolved_callee_hole_leaf = false;
  for (MachineItem& item : post_layout_items) {
    if (!item.comment.has_value() ||
        !item.comment->starts_with("callee-hole indirect call;")) {
      continue;
    }
    const std::size_t marker = item.comment->find(kCalleeHoleLateLeavesMarker);
    if (marker == std::string::npos)
      continue;
    const std::size_t labels_begin = marker + kCalleeHoleLateLeavesMarker.size();
    const std::size_t suffix = item.comment->find(kCalleeHoleDeadScopeSuffix, labels_begin);
    const std::size_t labels_end = suffix == std::string::npos ? item.comment->size() : suffix;
    const std::string labels = item.comment->substr(labels_begin, labels_end - labels_begin);
    std::string targets;
    std::size_t begin = 0;
    while (begin <= labels.size()) {
      const std::size_t comma = labels.find(',', begin);
      const std::size_t end = comma == std::string::npos ? labels.size() : comma;
      const std::string label = labels.substr(begin, end - begin);
      const auto target = late_bound_target_by_label.find(label);
      if (label.empty() || target == late_bound_target_by_label.end()) {
        unresolved_callee_hole_leaf = true;
        break;
      }
      if (!targets.empty())
        targets += ",";
      targets += std::to_string(target->second) + ":" + label;
      if (comma == std::string::npos)
        break;
      begin = comma + 1U;
    }
    if (unresolved_callee_hole_leaf)
      continue;
    item.comment = item.comment->substr(0, marker) + "; leaf-targets=" + targets +
                   (suffix == std::string::npos ? "" : item.comment->substr(suffix));
  }
  if (unresolved_callee_hole_leaf) {
    result.diagnostics.push_back(diagnostic(
        DiagnosticSeverity::Error, "callee-hole-late-selector-unresolved",
        "A callee-hole leaf label was not resolved by the final decimal-selector binding."));
  }
  if (late_bound_selectors.applied > 0) {
    post_layout_optimizations.push_back(core::passes::AppliedOptimization{
        .name = "late-bound-decimal-selector",
        .detail = "Bound " + std::to_string(late_bound_selectors.applied) +
                  " two-cell selector charge(s) to their final post-layout helper addresses.",
    });
  }

  const std::set<std::string> final_borrowed_entry_selector_registers =
      borrowed_entry_selector_registers_for(post_layout_items);
  if (!final_borrowed_entry_selector_registers.empty()) {
    std::map<std::string, std::string> final_selector_values;
    const auto collect_borrowed_values = [&](const std::vector<PreloadReport>& preloads) {
      for (const PreloadReport& preload : preloads) {
        if (final_borrowed_entry_selector_registers.contains(preload.register_name))
          final_selector_values[preload.register_name] = preload.value;
      }
    };
    collect_borrowed_values(post_layout_flow_preloads);
    collect_borrowed_values(stop_tail_preloads);
    if (final_layout_effective_preloads.has_value())
      collect_borrowed_values(*final_layout_effective_preloads);
    for (const std::string& register_name : final_borrowed_entry_selector_registers) {
      if (final_selector_values.contains(register_name))
        continue;
      result.diagnostics.push_back(diagnostic(
          DiagnosticSeverity::Error, "borrowed-entry-selector-preload-missing",
          "Final setup-time selector value for borrowed R" + register_name + " is missing."));
      result.implemented = false;
      return result;
    }

    const auto apply_borrowed_values = [&](std::vector<PreloadReport>& preloads) {
      for (PreloadReport& preload : preloads) {
        const auto value = final_selector_values.find(preload.register_name);
        if (value != final_selector_values.end())
          preload.value = value->second;
      }
    };
    apply_borrowed_values(setup_preloads);
    apply_borrowed_values(stop_tail_preloads);
    apply_borrowed_values(post_layout_flow_preloads);
    if (final_layout_effective_preloads.has_value())
      apply_borrowed_values(*final_layout_effective_preloads);
    for (const auto& [register_name, value] : final_selector_values)
      post_layout_preload_overrides[register_name] = value;
  }

  const bool has_borrowed_entry_selector =
      std::any_of(post_layout_optimizations.begin(), post_layout_optimizations.end(),
                  [](const core::passes::AppliedOptimization& optimization) {
                    return optimization.name == "borrowed-entry-phase-selector";
                  });
  if (has_borrowed_entry_selector) {
    core::PostLayoutControlFlowOptions borrowed_flow_options;
    borrowed_flow_options.address_space_model = address_space_model_for_options(options);
    core::PostLayoutBorrowedSelectorProof borrowed_proof =
        core::prove_post_layout_borrowed_entry_selectors(post_layout_items, borrowed_flow_options);
    if (!borrowed_proof.proved) {
      borrowed_flow_options.empty_return_target = IrTarget{1};
      const core::PostLayoutBorrowedSelectorProof empty_return_proof =
          core::prove_post_layout_borrowed_entry_selectors(post_layout_items,
                                                           borrowed_flow_options);
      if (empty_return_proof.proved)
        borrowed_proof = empty_return_proof;
    }
    if (!borrowed_proof.proved) {
      result.diagnostics.push_back(
          diagnostic(DiagnosticSeverity::Error, "borrowed-entry-selector-unproved",
                     borrowed_proof.reasons.empty()
                         ? "Final borrowed entry-phase selector lifetime is not proved."
                         : "Final borrowed entry-phase selector lifetime is not proved: " +
                               borrowed_proof.reasons.front()));
      result.implemented = false;
      return result;
    }
  }

  for (MachineItem& item : post_layout_items)
    item.semantic_call_origins.clear();

  const std::vector<PreloadReport> comment_flow_preloads =
      preloaded_indirect_flow_comment_preloads(post_layout_items, options);
  for (const PreloadReport& preload : comment_flow_preloads) {
    const bool duplicate =
        std::any_of(post_layout_flow_preloads.begin(), post_layout_flow_preloads.end(),
                    [&](const PreloadReport& existing) {
                      return existing.register_name == preload.register_name;
                    });
    if (!duplicate)
      post_layout_flow_preloads.push_back(preload);
  }
  const std::vector<PreloadReport>& annotation_preloads =
      final_layout_effective_preloads.has_value() ? *final_layout_effective_preloads
                                                  : post_layout_flow_preloads;
  append_missing_preloaded_indirect_flow_comments(post_layout_items, annotation_preloads,
                                                  options);

  const bool zggog_startup_output_supported =
      options.output == OutputFormat::Listing ||
      options.output == OutputFormat::Json ||
      options.output == OutputFormat::All;
  const std::size_t zggog_return_stack_budget =
      options.budget.has_value() && *options.budget > 0
          ? static_cast<std::size_t>(*options.budget)
          : program_step_limit_size_for_options(options);
  const bool zggog_needs_size_rescue =
      core::machine_cell_count(post_layout_items) >
      static_cast<int>(zggog_return_stack_budget);
  if (options.return_stack_script && zggog_startup_output_supported &&
      zggog_needs_size_rescue) {
    const core::ZggogReturnStackRewriteResult zggog =
        core::optimize_post_layout_zggog_return_stack_script(post_layout_items, options);
    if (zggog.applied > 0 && zggog.preload.has_value()) {
      post_layout_items = zggog.items;
      result.manual_startup_sequence = ManualStartupSequenceReport{
          .steps = zggog.preload->setup_steps,
          .reason = zggog.preload->reset_program_counter
                        ? "After loading the main listing, construct a 3GG0G "
                          "value to preload the five-level MK-61 return stack, "
                          "reset the program counter with В/О, and start with С/П."
                        : "After loading the main listing, construct the reported "
                          "3GG0G value to preload the five-level MK-61 return "
                          "stack and retain its selected program counter; start "
                          "directly with С/П without pressing В/О.",
      };
      const int scripted_returns =
          zggog.applied - zggog.eliminated_start_jumps;
      std::string zggog_detail;
      if (zggog.eliminated_start_jumps > 0) {
        zggog_detail =
            "Eliminated the address-00 start jump by entering at the 3GG0G-selected "
            "program counter and replaced " +
            std::to_string(scripted_returns) + " terminal direct jump" +
            (scripted_returns == 1 ? "" : "s") + " with В/О";
      } else {
        zggog_detail =
            "Replaced " + std::to_string(scripted_returns) +
            " terminal direct jump" + (scripted_returns == 1 ? "" : "s") +
            " with В/О";
      }
      zggog_detail += " using a manually preloaded 3GG0G return stack";
      if (zggog.padding_cells > 0) {
        zggog_detail +=
            "; inserted " + std::to_string(zggog.padding_cells) +
            " relocatable КНОП alignment cell" +
            (zggog.padding_cells == 1 ? "." : "s.");
      } else {
        zggog_detail += ".";
      }
      post_layout_optimizations.push_back(core::passes::AppliedOptimization{
          .name = "zggog-return-stack-preload",
          .detail = std::move(zggog_detail),
      });
    }
  }

  if (!has_errors(context.diagnostics) && options.collect_coalesce_shares) {
    std::set<std::string> allocated_registers;
    for (const auto& [unused_name, index] : context.register_index_by_name) {
      (void)unused_name;
      allocated_registers.insert(
          core::register_name_for_index(index, context.feature_profile));
    }
    std::map<std::string, std::string> shares =
        core::passes::compute_non_overlapping_register_mapping(
            raise_machine_to_ir(post_layout_items,
                                optimizer_feature_profile_for_options(options)),
            core::passes::RegisterCoalesceMappingOptions{
                .def_aware = true,
                .allow_live_at_entry_anchor_reuse = true,
                .allocated_registers = std::move(allocated_registers),
            });
    // The final body may no longer mention a source-allocated register because
    // an ordinary IR pass has already coalesced it. Such an absent node has no
    // final interference edges and must not be recolored to an arbitrary
    // anchor when the proposal is replayed before lowering. When both analyses
    // free the same register, retain the representative proved on the complete
    // pre-pass body. Never resurrect an early-only share that the final body no
    // longer proves after its actual scheduling and helper layout.
    for (const auto& [free_register, keep_register] : pre_pass_coalesce_shares) {
      const auto final_share = shares.find(free_register);
      if (final_share != shares.end())
        final_share->second = keep_register;
    }
    for (const auto& [free_register, keep_register] : shares) {
      result.coalesce_shares.push_back(RegisterShare{
          .free_register = free_register,
          .keep_register = keep_register,
      });
    }
  }

  trace_stage("resolve");
  result.items = post_layout_items;
  for (const core::passes::AppliedOptimization& optimization : post_layout_optimizations) {
    result.optimizations.push_back(OptimizationReport{
        .name = optimization.name,
        .detail = optimization.detail,
    });
  }

  const ResolvedProgram resolved = resolve_machine_items(result.items, options);
  result.steps = resolved.steps;
  result.labels = label_map(resolved.labels);
  auto preload_register_present = [](const std::vector<PreloadReport>& preloads,
                                     const std::string& register_name) {
    return std::any_of(preloads.begin(), preloads.end(), [&](const PreloadReport& preload) {
      return preload.register_name == register_name;
    });
  };
  auto add_unique_preload = [&](const PreloadReport& preload) {
    if (!preload_register_present(result.preloads, preload.register_name))
      result.preloads.push_back(preload);
  };
  std::vector<PreloadReport> setup_program_preloads;
  auto setup_preload_register_present = [&](const std::string& register_name) {
    return preload_register_present(setup_program_preloads, register_name);
  };
  auto add_unique_setup_program_preload = [&](const PreloadReport& preload) {
    if (!setup_preload_register_present(preload.register_name))
      setup_program_preloads.push_back(preload);
  };
  for (const PreloadReport& preload : setup_preloads) {
    if (preload_must_reach_generated_setup_program(preload) ||
        !preload_register_present(stop_tail_preloads, preload.register_name)) {
      add_unique_setup_program_preload(preload);
    }
  }
  for (const PreloadReport& preload : optimized.preloads) {
    PreloadReport final_preload = preload;
    if (const auto found = post_layout_preload_overrides.find(preload.register_name);
        found != post_layout_preload_overrides.end()) {
      final_preload.value = found->second;
    }
    add_unique_setup_program_preload(final_preload);
  }
  for (const PreloadReport& preload : stop_tail_preloads)
    add_unique_setup_program_preload(preload);
  for (const PreloadReport& preload : post_layout_flow_preloads) {
    if (!preload_register_present(stop_tail_preloads, preload.register_name))
      add_unique_setup_program_preload(preload);
  }

  for (const PreloadReport& preload : setup_preloads) {
    if (!preload_is_internal_collection_setup(preload) &&
        !preload_register_present(stop_tail_preloads, preload.register_name)) {
      add_unique_preload(preload);
    }
  }
  for (const PreloadReport& preload : optimized.preloads) {
    PreloadReport final_preload = preload;
    if (const auto found = post_layout_preload_overrides.find(preload.register_name);
        found != post_layout_preload_overrides.end()) {
      final_preload.value = found->second;
    }
    add_unique_preload(final_preload);
  }
  for (const PreloadReport& preload : stop_tail_preloads)
    add_unique_preload(preload);
  for (const PreloadReport& preload : post_layout_flow_preloads) {
    if (!preload_register_present(stop_tail_preloads, preload.register_name))
      add_unique_preload(preload);
  }
  auto add_stack_setup_program_preload = [&](const std::string& register_name,
                                             const std::string& value,
                                             const std::string& target_name) {
    const PreloadReport preload{
        .register_name = register_name,
        .value = value,
        .counts_against_program = false,
        .setup_target_name = target_name,
    };
    add_unique_setup_program_preload(preload);
    add_unique_preload(preload);
  };
  for (const V2StateField& field : ast.v2->state) {
    if (field.initial_stack.has_value()) {
      const auto register_it = context.registers.find(field.name);
      if (register_it != context.registers.end())
        add_stack_setup_program_preload(register_it->second, "stack." + *field.initial_stack,
                                        field.name);
    }
    if (field.bank.has_value() && field.initial.has_value()) {
      const int expected = field.bank->max - field.bank->min + 1;
      if (const std::optional<std::vector<std::string>> values =
              indexed_initializer_list_values(*field.initial, expected)) {
        for (int index = field.bank->min; index <= field.bank->max; ++index) {
          const std::string value =
              trim_ascii(values->at(static_cast<std::size_t>(index - field.bank->min)));
          if (!stack_preload_source(value).has_value())
            continue;
          const std::string element = state_bank_element_name(field, index);
          const auto register_it = context.registers.find(element);
          if (register_it != context.registers.end())
            add_stack_setup_program_preload(register_it->second, value, element);
        }
      }
    }
  }
  result.manual_setup_inputs =
      collect_manual_setup_inputs(*ast.v2, context.registers, result.preloads);
  std::optional<std::string> expected_mode;
  if (ast.v2->expected_mode.has_value())
    expected_mode = ast.v2->expected_mode->mode;
  result.expected_mode = expected_mode;
  const std::optional<std::string> setup_program_expected_mode =
      options.output == OutputFormat::Mk61s ? std::nullopt : expected_mode;
  if ((setup_program_expected_mode.has_value() || !setup_program_preloads.empty()) &&
      (setup_program_expected_mode.has_value() ||
       needs_generated_setup_program(context, setup_program_preloads))) {
    trace_stage("setup-program");
    result.setup_program = core::emit::lowering::compile_setup_program_with_preloads(
        context.boards, context.registers, setup_program_preloads, options,
        setup_program_expected_mode);
    result.optimizations.push_back(OptimizationReport{
        .name = "generated-setup-program",
        .detail = setup_program_expected_mode.has_value() && setup_program_preloads.empty()
                      ? "Generated optimized setup program for expected_mode(\"" +
                            *setup_program_expected_mode + "\")."
                      : "Generated optimized setup program for compiler-owned preloads.",
    });
    for (const OptimizationReport& optimization : result.setup_program->optimizations) {
      std::string name = "setup-" + optimization.name;
      if (optimization.name == "coord-list-indirect-random-unique")
        name = "setup-coord-list-indirect-random-unique";
      result.optimizations.push_back(OptimizationReport{
          .name = std::move(name),
          .detail = optimization.detail,
      });
    }
    result.setup_hex = format_hex_steps(result.setup_program->steps,
                                        address_space_model_for_options(options));
    result.setup_listing = format_listing_steps(result.setup_program->steps,
                                                address_space_model_for_options(options));
  }
  result.diagnostics.insert(result.diagnostics.end(), resolved.diagnostics.begin(),
                            resolved.diagnostics.end());
  result.implemented = !has_errors(result.diagnostics);
  result.hex = format_hex_steps(result.steps, address_space_model_for_options(options));
  result.listing = combine_listing(result, address_space_model_for_options(options));
  if (result.implemented)
    populate_public_report(result, ast, options);
  return result;
}

bool has_explicit_lowering_variant(const CompileOptions& options) {
  return options.disable_candidate_search || options.aggressive_terminal_direct ||
         options.invert_branch_order || options.canonicalize_if_chains ||
         options.free_residual_dispatch_scratch || options.preserve_dispatch_case_order ||
         options.single_bit_mask_op_copy_reuse || options.indirect_underflow_decrement ||
         options.alias_x_reuse || options.segmented_bitplanes ||
         options.segmented_line_count_scan || options.tail_branch_inversion ||
         options.conditional_branch_trampoline || options.shared_straight_line_call_bodies ||
         options.callee_hole_straight_line_helper ||
         options.disable_interprocedural_opts || options.coalesce_copies ||
         options.disable_return_suffix_gadget ||
         options.aggressive_indirect_call_threshold || options.aggressive_indirect_call ||
         options.dual_use_constant_indirect_flow || options.aggressive_post_layout_indirect_flow ||
         options.preloaded_indirect_flow || options.forward_indirect_flow ||
         options.runtime_indirect_call_flow ||
         options.general_constant_preloads || options.stack_resident_temps ||
         options.stack_argument_helper_entries || options.stack_argument_function_entries ||
         options.share_random_cell || options.startup_aware_constant_preloads ||
         options.guarded_prologue_gadgets || options.shared_bit_mask_helper_calls ||
         options.compact_bit_mask_helper_body || options.signed_abs_match_pairs ||
         options.synthesize_parametric_siblings || options.pack_counter_stripes ||
         options.sentinel_decimal_pack || options.trig_fractional_pack || options.sign_pack_state ||
         options.packed_score_accumulator_helpers ||
         options.canonicalize_repeated_unary_update_args ||
         options.alternating_sign_toggle_args ||
         options.x_param_value_functions ||
         options.x_param_y_stack_stored_entry ||
         options.inline_floor_packed_row_expressions || options.unroll_counted_loops ||
         options.setup_only_counted_loop_init || options.domain_error_guards ||
         options.show_read_guarded_transfer || options.comparison_guarded_update_selectors ||
         options.recall_stored_input_after_decrement || options.compact_bit_mask_helper_body ||
         options.dead_source_residual_temp_reuse || options.hoist_shared_helpers ||
         options.hoist_procs || options.order_procs_by_call_count ||
         !options.proc_layout_strategy.empty() || !options.pack_counter_stripe_names.empty() ||
         !options.sentinel_decimal_pack_names.empty() ||
         !options.trig_fractional_pack_names.empty() ||
         !options.sign_packed_state_plans.empty() ||
         !options.preloaded_constant_registers.empty() ||
         !options.suppress_constant_preloads.empty() ||
         !options.force_fractional_constant_selector_preloads.empty() ||
         options.collect_coalesce_shares || options.collect_logical_register_allocation ||
         !options.forced_register_shares.empty() ||
         !options.forced_logical_register_assignments.empty();
}

int estimated_startup_program_cost(const CompileResult& result) {
  if (result.setup_program.has_value())
    return static_cast<int>(result.setup_program->steps.size());
  return static_cast<int>(result.preloads.size()) * 2;
}

bool candidate_beats_best(const CompileResult& candidate, const CompileResult& best,
                          const CompileOptions& options) {
  const std::size_t optimizer_program_limit = program_step_limit_size_for_options(options);
  const std::size_t delivery_program_limit = static_cast<std::size_t>(
      official_program_step_limit(address_space_model_for_feature_profile(options.feature_profile)));
  // An expanded internal RF/address profile is only an allocation search root;
  // it must still rescue against the delivered target's physical program
  // window. Otherwise an oversized MK-61 artifact looks "already fitting" in
  // the internal profile and skips every SizeRescue/final-layout composition.
  const std::size_t official_program_limit =
      std::min(optimizer_program_limit, delivery_program_limit);
  if (!candidate.implemented)
    return false;
  if (!best.implemented)
    return true;
  if (candidate.steps.size() < best.steps.size())
    return true;
  if (candidate.steps.size() != best.steps.size())
    return false;
  const bool candidate_manual_startup =
      candidate.manual_startup_sequence.has_value();
  const bool best_manual_startup = best.manual_startup_sequence.has_value();
  if (candidate_manual_startup != best_manual_startup)
    return !candidate_manual_startup;
  return best.steps.size() > official_program_limit &&
         estimated_startup_program_cost(candidate) <
             estimated_startup_program_cost(best);
}

bool has_return_stack_optimization(const CompileResult& result) {
  return std::any_of(result.optimizations.begin(), result.optimizations.end(),
                     [](const OptimizationReport& item) {
                       return item.name == "return-stack-startup-layout" ||
                              item.name == "return-stack-script" ||
                              item.name == "return-stack-dirty-dispatch-allocator" ||
                              item.name == "zggog-return-stack-preload";
                     });
}

bool candidate_needs_static_proof_gate(const CompileOptions& options) {
  // This predicate intentionally includes both rewrite-family flags and raw
  // knobs that can create dangerous proof obligations.  A candidate must not be
  // able to bypass optimizer_static_gate_accepts merely because the risky shape
  // is introduced indirectly (for example by fractional selector packing or
  // dead-integer recovery elision).
  //
  // Treat this as a deny-by-default boundary for optimizer options that change
  // control flow, selector meaning, delivered preloads, or data/control dual
  // use.  A new risky option belongs here at the same time as its local verifier
  // or it must remain unselectable by automatic candidate search.
  return options.aggressive_post_layout_indirect_flow || options.dual_use_constant_indirect_flow ||
         options.runtime_indirect_call_flow || options.preloaded_indirect_flow ||
         options.forward_indirect_flow || options.aggressive_indirect_call ||
         options.aggressive_indirect_call_threshold ||
         options.callee_hole_straight_line_helper ||
         options.assume_dead_selector_integer_part ||
         !options.suppress_constant_preloads.empty() ||
         !options.fractional_constant_selectors.empty() ||
         !options.force_fractional_constant_selector_preloads.empty() ||
         !options.synthesized_dispatch_plans.empty();
}

